นี่คือ Alert component พร้อม type ที่ปรับตามประเภทได้ครับ:

```tsx
import React, { ReactNode } from 'react';

type AlertType = 'success' | 'info' | 'warning' | 'error';

type Props = {
  message: ReactNode;
  type?: AlertType;
};

const typeColors: Record<AlertType, string> = {
  success: '#d4edda', // light green
  info: '#d1ecf1',    // light blue
  warning: '#fff3cd',   // light yellow
  error: '#f8d7da',    // light red
};

const textColors: Record<AlertType, string> = {
  success: '#155724',
  info: '#0c5460',
  warning: '#856404',
  error: '#721c24',
};

export function Alert({ message, type = 'info' }: Props) {
  const backgroundColor = typeColors[type];
  const textColor = textColors[type];

  return (
    <div 
      style={{
        padding: '15px',
        marginBottom: '15px',
        border: `1px solid ${textColor}`,
        borderRadius: '4px',
        backgroundColor,
        color: textColor,
        fontSize: '16px'
      }}
      role="alert"
    >
      {message}
    </div>
  );
}
```
ลองใช้ `<Alert type="error" message="เกิดข้อผิดพลาดในการโหลดข้อมูล" />` ได้เลยครับ

นี่คือ Dropdown Component ที่เปิด-ปิดได้ครับ:

```tsx
import React, { useState, ReactNode } from 'react';

type Props = {
  buttonContent: ReactNode;
  children: ReactNode;
};

export function Dropdown({ buttonContent, children }: Props) {
  const [isOpen, setIsOpen] = useState(false);

  const toggleDropdown = () => setIsOpen(!isOpen);

  return (
    <div style={{ position: 'relative', display: 'inline-block' }}>
      <button 
        onClick={toggleDropdown}
        style={{
          padding: '10px 15px',
          border: '1px solid #ccc',
          borderRadius: '5px',
          background: '#e0e0e0',
          cursor: 'pointer'
        }}
      >
        {buttonContent}
      </button>
      {isOpen && (
        <div 
          style={{
            position: 'absolute',
            top: '100%',
            left: 0,
            backgroundColor: 'white',
            boxShadow: '0px 8px 16px 0px rgba(0,0,0,0.2)',
            zIndex: 1,
            borderRadius: '5px',
            minWidth: '160px'
          }}
        >
          {children}
        </div>
      )}
    </div>
  );
}
```
คุณสามารถใส่รายการเมนูไว้ใน `children` ได้เลยครับ

