นี่คือ Tab Component ที่ใช้งานได้ง่ายๆ ครับ:

```tsx
import React, { useState, ReactNode } from 'react';

type TabItem = {
  title: string;
  content: ReactNode;
};

type Props = {
  tabs: TabItem[];
};

export function Tabs({ tabs }: Props) {
  const [activeTab, setActiveTab] = useState(0);

  return (
    <div>
      <div style={{ borderBottom: '1px solid #ccc', display: 'flex' }}>
        {tabs.map((tab, index) => (
          <button
            key={index}
            onClick={() => setActiveTab(index)}
            style={{
              padding: '10px 15px',
              border: 'none',
              borderBottom: index === activeTab ? '2px solid #007bff' : '2px solid transparent',
