```python
import csv

def calculate_column_sum(file_path: str, column_name: str) -> float:
    total_sum = 0.0
    try:
        with open(file_path, 'r', newline='', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            if column_name not in reader.fieldnames:
                print(f"Error: Column '{column_name}' not found in the CSV file.")
                return 0.0

            for row in reader:
                try:
                    value = float(row[column_name])
                    total_sum += value
                except (ValueError, TypeError):
                    # Skip rows where the value is not a valid number
                    continue
    except FileNotFoundError:
        print(f"Error: The file '{file_path}' was not found.")
        return 0.0
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return 0.0

    return round(total_sum, 2)

if __name__ == "__main__":
    # data.csv ဖိုင်ထဲက 'Amount' ကော်လံရဲ့ စုစုပေါင်းကို တွက်မယ်
    # data.csv ဖိုင်ထဲမှာ 'Amount' ကော်လံနဲ့ ဂဏန်းတန်ဖိုးတွေရှိတယ်ဆိုပါစို့။
    total = calculate_column_sum('transactions.csv', 'Amount')
    print(f"Total sum of 'Amount' column: {total}")
```
