```go
package main

import (
	"fmt"
	"os"
)

func main() {
	file, err := os.Open("data.txt")
	if err != nil {
		fmt.Println("Error opening file:", err)
		return
	}
	defer file.Close() // Ensure file is closed

	bytes := make([]byte, 100)
	_, err = file.Read(bytes)
	if err != nil {
		fmt.Println("Error reading file:", err)
		return
	}

	fmt.Println("Read content:", string(bytes))
}
```
អាច refactor ទៅជា:
```go
package main

import (
	"fmt"
	"io/ioutil" // For simpler read if whole file is needed
)

func readFileContent(filename string) (string, error) {
	data, err := ioutil.ReadFile(filename)
	if err != nil {
		return "", fmt.Errorf("failed to read file '%s': %w", filename, err)
	}
	return string(data), nil
}

func main() {
	content, err := readFileContent("data.txt")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("File content:", content)
}
```
ការរៀបចំ logic ចូលទៅក្នុង function តែមួយជាមួយ error handling ធ្វើឱ្យ `main` function របស់អ្នកកាន់តែស្អាត និងផ្តោតលើលំហូរកម្មវិធីមែនទេ?

