ໄດ້ເລີຍ! ນີ້ແມ່ນຟັງຊັນ C# ເພື່ອກວດສອບ Palindrome:

```csharp
using System;
using System.Linq;

public class PalindromeChecker
{
    public static bool IsPalindrome(string word)
    {
        if (string.IsNullOrEmpty(word)) return false;
        string cleanedWord = new string(word.Where(char.IsLetterOrDigit).ToArray()).ToLower();
        string reversedWord = new string(cleanedWord.Reverse().ToArray());
        return cleanedWord.Equals(reversedWord);
    }

    public static void Main(string[] args)
    {
        Console.WriteLine(IsPalindrome("madam"));       // True
        Console.WriteLine(IsPalindrome("A man, a plan, a canal: Panama")); // True
        Console.WriteLine(IsPalindrome("hello"));       // False
    }
}
```
