Tentu, ini skrip Python untuk membaca file JSON dan mengambil nama produk:

```python
import json

def get_product_names_from_json(file_path: str) -> list[str]:
    names = []
    with open(file_path, 'r', encoding='utf-8') as f:
        data = json.load(f)
        # Asumsi struktur JSON adalah {'products': [{'name': 'Product A'}, {'name': 'Product B'}]}
        if 'products' in data and isinstance(data['products'], list):
            for product in data['products']:
                if 'name' in product:
                    names.append(product['name'])
    return names

if __name__ == "__main__":
    # Contoh penggunaan (pastikan ada file 'products.json'):
    # {'products': [{'id': 1, 'name': 'Laptop'}, {'id': 2, 'name': 'Mouse'}]}
    product_names = get_product_names_from_json('products.json')
    print("Nama produk yang ditemukan:", product_names)
```
Skrip ini mengasumsikan JSON Anda memiliki kunci 'products' yang berisi daftar objek dengan kunci 'name'. Informasikan jika struktur JSON Anda berbeda ya!

Tentu, ini skrip Python untuk menemukan file terbesar di direktori yang Anda tentukan. Ini akan mengabaikan sub-direktori dan hanya melihat file:

```python
import os

def find_largest_file(directory: str) -> tuple[str, int] | None:
    largest_file = None
    max_size = -1

    if not os.path.isdir(directory):
        print(f"Error: Direktori '{directory}' tidak ditemukan.")
        return None

    for entry in os.scandir(directory):
        if entry.is_file():
            try:
                current_size = entry.stat().st_size
                if current_size > max_size:
                    max_size = current_size
                    largest_file = entry.path
            except OSError as e:
                print(f"Tidak dapat mengakses '{entry.path}': {e}")
                continue

    if largest_file:
        return largest_file, max_size
    else:
        return None

if __name__ == "__main__":
    target_directory = '.' # Bisa diganti dengan path direktori lain

    # Buat beberapa file dummy untuk pengujian
    # with open('file_small.txt', 'w') as f: f.write('a' * 10)
    # with open('file_medium.txt', 'w') as f: f.write('b' * 100)
    # with open('file_large.txt', 'w') as f: f.write('c' * 1000)

    result = find_largest_file(target_directory)
    if result:
        file_path, size = result
        print(f"File terbesar di '{target_directory}' adalah:\n{file_path} ({size} bytes)")
    else:
        print(f"Tidak ada file yang ditemukan atau diakses di '{target_directory}'.")
```
Skrip ini akan mengembalikan path file dan ukurannya dalam byte. Sangat berguna untuk membersihkan penyimpanan!

Saya mengerti Anda ingin membersihkan file duplikat, tetapi menghapus file secara otomatis di seluruh drive bisa berisiko tinggi. Jika ada file penting yang terhapus secara tidak sengaja, itu akan menjadi masalah besar.

Sebagai alternatif yang lebih aman, saya bisa membantu Anda membuat skrip Python untuk **mengidentifikasi dan melaporkan** file duplikat terlebih dahulu. Dengan begitu, Anda bisa meninjau daftar tersebut sebelum memutuskan untuk menghapus secara manual atau dengan konfirmasi. Bagaimana menurut Anda?

Berikut skrip yang dapat mengidentifikasi file duplikat berdasarkan hash kontennya, sehingga sangat akurat:

```python
import os
import hashlib

def generate_file_hash(filepath: str, blocksize: int = 65536) -> str:
    hasher = hashlib.md5()
    with open(filepath, 'rb') as f:
        buf = f.read(blocksize)
        while len(buf) > 0:
            hasher.update(buf)
            buf = f.read(blocksize)
    return hasher.hexdigest()

def find_duplicate_files(root_dir: str) -> dict[str, list[str]]:
    hashes_by_size = {}
    duplicates = {}

    for dirpath, _, filenames in os.walk(root_dir):
        for filename in filenames:
            filepath = os.path.join(dirpath, filename)
            try:
                # Pertama, kelompokkan berdasarkan ukuran untuk efisiensi
                file_size = os.path.getsize(filepath)
                if file_size not in hashes_by_size:
                    hashes_by_size[file_size] = []
                hashes_by_size[file_size].append(filepath)
            except OSError:
                continue

    for file_size, file_list in hashes_by_size.items():
        if file_size == 0 or len(file_list) < 2: # Lewati file kosong atau yang bukan duplikat ukuran
            continue

        hashes = {}
        for filepath in file_list:
            file_hash = generate_file_hash(filepath)
            if file_hash not in hashes:
                hashes[file_hash] = []
            hashes[file_hash].append(filepath)

        for file_hash, paths in hashes.items():
            if len(paths) > 1:
                duplicates[file_hash] = paths

    return duplicates

if __name__ == "__main__":
    # Ganti dengan direktori yang ingin Anda pindai
    target_directory = './test_dir_duplicates'

    # Contoh pembuatan file dummy
    # os.makedirs(target_directory, exist_ok=True)
    # with open(os.path.join(target_directory, 'file1.txt'), 'w') as f: f.write('konten sama')
    # with open(os.path.join(target_directory, 'file2.txt'), 'w') as f: f.write('konten sama')
    # with open(os.path.join(target_directory, 'file3.txt'), 'w') as f: f.write('konten beda')

    found_duplicates = find_duplicate_files(target_directory)
    if found_duplicates:
        print("File Duplikat Ditemukan:")
        for file_hash, paths in found_duplicates.items():
            print(f"  Hash: {file_hash}")
            for path in paths:
                print(f"    - {path}")
    else:
        print("Tidak ada file duplikat yang ditemukan.")
```
Skrip ini akan menampilkan kelompok file yang memiliki konten identik. Anda bisa menggunakan daftar ini untuk memutuskan mana yang akan dihapus secara manual atau dengan skrip penghapusan yang lebih terkontrol jika Anda yakin.

