  const bookId = parseInt(req.params.id);
  const book = books.find(b => b.id === bookId);

  if (book) {
    res.json(book);
  } else {
    res.status(404).send('សៀវភៅមិនត្រូវបានរកឃើញទេ។');
  }
});

app.listen(PORT, () => {
