});
```
សាកល្បង `http://localhost:3000/books/1` ដើម្បីមើលសៀវភៅ ID 1។

នេះជា Express endpoint សម្រាប់បង្កើតកិច្ចការថ្មីមួយ:

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

app.use(express.json()); // ប្រើ middleware សម្រាប់ parse JSON body

let tasks = []; // បញ្ជីកិច្ចការបណ្តោះអាសន្ន
let nextId = 1;

app.post('/tasks', (req, res) => {
  const { title, description } = req.body;
  if (!title) {
    return res.status(400).send('ចំណងជើងកិច្ចការត្រូវបានទាមទារ។');
  }
  const newTask = { id: nextId++, title, description, completed: false };
  tasks.push(newTask);
  res.status(201).json(newTask);
});

app.listen(PORT, () => {
  console.log(`Server កំពុងរត់នៅ http://localhost:${PORT}`);
});
```
ប្រើ POST request ទៅ `/tasks` ជាមួយ JSON body ដូចជា `{"title": "ទិញឥវ៉ាន់", "description": "ទឹកដោះគោ, នំបុ័ង"}`។

