```go
package main

import (
	"fmt"
	"strings"
)

func isPalindrome(s string) bool {
	// แปลงเป็นตัวพิมพ์เล็กและลบช่องว่าง
	s = strings.ToLower(strings.ReplaceAll(s, " ", ""))

	// ตรวจสอบ Palindrome
	for i := 0; i < len(s)/2; i++ {
		if s[i] != s[len(s)-1-i] {
			return false
		}
	}
	return true
}

func main() {
	fmt.Printf("\"madam\" เป็น Palindrome: %t\n", isPalindrome("madam"))
	fmt.Printf("\"Racecar\" เป็น Palindrome: %t\n", isPalindrome("Racecar"))
	fmt.Printf("\"hello\" เป็น Palindrome: %t\n", isPalindrome("hello"))
	fmt.Printf("\"A man a plan a canal Panama\" เป็น Palindrome: %t\n", isPalindrome("A man a plan a canal Panama"))
}
```
