```csharp
using System;
using System.Globalization;

public static class StringExtensions
{
    public static string ToTitleCase(this string input)
    {
        if (string.IsNullOrWhiteSpace(input))
        {
            return input;
        }
        TextInfo textInfo = CultureInfo.CurrentCulture.TextInfo;
        return textInfo.ToTitleCase(input);
    }

    public static void Main(string[] args)
    {
        string sentence1 = "hello world";
        string sentence2 = "the quick brown fox";
        string sentence3 = "c# programming";

        Console.WriteLine($"'{sentence1}' -> '{sentence1.ToTitleCase()}'");
        Console.WriteLine($"'{sentence2}' -> '{sentence2.ToTitleCase()}'");
        Console.WriteLine($"'{sentence3}' -> '{sentence3.ToTitleCase()}'");
    }
}
```
