function truncateString(string $text, int $maxLength = 100): string {
    if (strlen($text) <= $maxLength) {
        return $text;
    }
    $truncatedText = substr($text, 0, $maxLength - 3); // -3 สำหรับ '...'
    return $truncatedText . '...';
}

// ตัวอย่างการใช้งาน
$longText = "นี่คือข้อความที่ยาวมาก เพื่อทดสอบการตัดคำในฟังก์ชัน truncateString ของเรา";
$shortText = "สั้นๆ";

echo "ตัดที่ 20 ตัวอักษร: " . truncateString($longText, 20) . "\n";
echo "ตัดที่ 50 ตัวอักษร: " . truncateString($longText, 50) . "\n";
echo "ข้อความสั้น: " . truncateString($shortText, 20) . "\n";

?>
```
