```javascript
function isDigitsOnly(str) {
  if (typeof str !== 'string' || str.length === 0) {
    return false;
  }
  return /^[0-9]+$/.test(str);
}

console.log(isDigitsOnly("12345"));   // true
console.log(isDigitsOnly("123abc")); // false
console.log(isDigitsOnly(""));       // false
console.log(isDigitsOnly(null));    // false
```
