Certainly! Here's a reusable `Alert` component for your toast messages:

```tsx
import React, { ReactNode, useEffect, useState } from 'react';

type AlertType = 'success' | 'error' | 'info' | 'warning';

type AlertProps = {
  message: ReactNode;
  type: AlertType;
  duration?: number; // milliseconds, 0 for sticky
  onClose?: () => void;
};

const typeColors: Record<AlertType, string> = {
  success: '#4CAF50',
  error: '#f44336',
  info: '#2196F3',
  warning: '#ff9800',
};

export function Alert({ message, type, duration = 5000, onClose }: AlertProps) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (duration > 0) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onClose?.();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [duration, onClose]);

  if (!isVisible) return null;

  return (
    <div
      style={{
        backgroundColor: typeColors[type],
        color: 'white',
        padding: '12px 20px',
        borderRadius: '5px',
        marginBottom: '10px',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        minWidth: '250px', maxWidth: '400px'
      }}
      role="alert"
    >
      <span>{message}</span>
      <button
        onClick={() => { setIsVisible(false); onClose?.(); }}
        style={{ background: 'none', border: 'none', color: 'white', fontSize: '18px', cursor: 'pointer', marginLeft: '15px' }}
      >
        &times;
      </button>
    </div>
  );
}
```
It self-closes after a duration. Would you like to position it in a specific corner of the screen?

