```python
import csv

def merge_csv_by_id(employees_path: str, salaries_path: str, output_path: str) -> None:
    employees = {}
    with open(employees_path, 'r', newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            employees[row['ID']] = row # Anggap 'ID' adalah kunci unik

    merged_data = []
    with open(salaries_path, 'r', newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            employee_id = row['ID']
            if employee_id in employees:
                # Gabungkan data dari kedua-dua fail
                merged_row = {**employees[employee_id], **row}
                merged_data.append(merged_row)

    if merged_data:
        fieldnames = list(merged_data[0].keys())
        with open(output_path, 'w', newline='', encoding='utf-8') as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(merged_data)
        print(f"Fail gabungan berjaya disimpan ke {output_path}")
    else:
        print("Tiada data untuk digabungkan atau ID tidak sepadan.")

if __name__ == "__main__":
    # Contoh fail
    with open('employees.csv', 'w', newline='') as f: csv.writer(f).writerows([['ID', 'Nama'], ['1', 'Ali'], ['2', 'Budi']]);
    with open('salaries.csv', 'w', newline='') as f: csv.writer(f).writerows([['ID', 'Gaji'], ['1', '5000'], ['2', '6000'], ['3', '7000']]);

    merge_csv_by_id('employees.csv', 'salaries.csv', 'merged_data.csv')
```
