```php
<?php
$users = [
    ['name' => 'Alice', 'age' => 20],
    ['name' => 'Bob', 'age' => 17],
    ['name' => 'Charlie', 'age' => 25],
];

// Original (loop-based)
// $adultNames = [];
// foreach ($users as $user) {
//     if ($user['age'] >= 18) {
//         $adultNames[] = $user['name'];
//     }
// }

// Refactored (cleaner)
$adultUsers = array_filter($users, fn($user) => $user['age'] >= 18);
$adultNames = array_map(fn($user) => $user['name'], $adultUsers);

print_r($adultNames); // Array ( [0] => Alice [1] => Charlie )
?>
```
