ໄດ້ເລີຍ! ນີ້ແມ່ນ API ແບບ GET ງ່າຍໆສຳລັບ Express.js ເພື່ອດຶງລາຍຊື່ຜູ້ໃຊ້:

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

// ຂໍ້ມູນຜູ້ໃຊ້ຕົວຢ່າງ
const users = [
  { id: 1, name: 'ສຸວັນນາ', email: 'souvanna@example.com' },
  { id: 2, name: 'ວິໄລ', email: 'vilay@example.com' }
];

// ເສັ້ນທາງ GET ເພື່ອດຶງລາຍຊື່ຜູ້ໃຊ້ທັງໝົດ
app.get('/users', (req, res) => {
  res.json(users);
});

app.listen(PORT, () => {
  console.log(`ເຊີບເວີກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${PORT}`);
});
```
ບັນທຶກເປັນ `app.js` ແລ້ວໃຊ້ `node app.js` ເພື່ອແລ່ນໄດ້ເລີຍ. ຢາກໃຫ້ເພີ່ມຟັງຊັນການຄົ້ນຫາບໍ່?

ສິ່ງນີ້ສຳຄັນຫຼາຍ! ນີ້ແມ່ນ endpoint ແບບ GET ສໍາລັບ Express.js ທີ່ດຶງຜະລິດຕະພັນດ້ວຍ ID ແລະຈັດການກໍລະນີທີ່ບໍ່ພົບຂໍ້ມູນຢ່າງຖືກຕ້ອງ:

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

const products = [
  { id: 1, name: 'ກາເຟ', price: 15000 },
  { id: 2, name: 'ຊາຂຽວ', price: 12000 },
  { id: 3, name: 'ນ້ຳໝາກໄມ້', price: 10000 }
];

app.get('/products/:id', (req, res) => {
  const productId = parseInt(req.params.id);
  const product = products.find(p => p.id === productId);

  if (product) {
    res.json(product);
  } else {
    res.status(404).json({ message: 'ບໍ່ພົບຜະລິດຕະພັນ' });
  }
});

app.listen(PORT, () => {
  console.log(`ເຊີບເວີກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${PORT}`);
});
```
ຖ້າບໍ່ພົບ, ມັນຈະສົ່ງ status 404 (Not Found). ງ່າຍໆເລີຍແມ່ນບໍ່? ຢາກໃຫ້ເພີ່ມການກວດສອບ ID ທີ່ບໍ່ແມ່ນຕົວເລກບໍ່?

ແນ່ນອນ! ນີ້ແມ່ນ endpoint ແບບ PUT ສໍາລັບ FastAPI ເພື່ອອັບເດດຜູ້ໃຊ້, ພ້ອມດ້ວຍການຈັດການກໍລະນີທີ່ບໍ່ພົບຜູ້ໃຊ້:

```python
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

class UserUpdate(BaseModel):
    name: str | None = None
    email: str | None = None

users_db = {
    1: {"name": "ສຸວັນນາ", "email": "souvanna@example.com"},
    2: {"name": "ວິໄລ", "email": "vilay@example.com"}
} # ຖານຂໍ້ມູນຈໍາລອງ

@app.put("/users/{user_id}")
async def update_user(user_id: int, user_update: UserUpdate):
    if user_id not in users_db:
        raise HTTPException(status_code=404, detail="ບໍ່ພົບຜູ້ໃຊ້")

    current_user = users_db[user_id]
    update_data = user_update.dict(exclude_unset=True)
    for key, value in update_data.items():
        current_user[key] = value

    return {"message": "ອັບເດດຜູ້ໃຊ້ສໍາເລັດ", "user": current_user}

```
ມັນໃຊ້ Pydantic ເພື່ອຮັບຂໍ້ມູນທີ່ອັບເດດ. ຖ້າບໍ່ພົບຜູ້ໃຊ້, ມັນຈະສົ່ງ HTTP 404. ງ່າຍ ແລະ ຖືກຕ້ອງ! ຢາກໃຫ້ເພີ່ມການກວດສອບອີເມວທີ່ເປັນເອກະລັກບໍ່?

ໄດ້ເລີຍ! ນີ້ແມ່ນ route ແບບ DELETE ດ້ວຍ Express.js ເພື່ອລຶບໂພສໂດຍໃຊ້ ID, ພ້ອມດ້ວຍການຈັດການກໍລະນີທີ່ບໍ່ພົບໂພສ:

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

let posts = [
  { id: 1, title: 'ໂພສທໍາອິດ', content: 'ເນື້ອໃນໂພສ...' },
  { id: 2, title: 'ໂພສທີສອງ', content: 'ເນື້ອໃນອື່ນໆ...' }
]; // ຖານຂໍ້ມູນຈໍາລອງ

app.delete('/posts/:id', (req, res) => {
  const postId = parseInt(req.params.id);
  const initialLength = posts.length;
  posts = posts.filter(post => post.id !== postId);

  if (posts.length < initialLength) {
    res.status(200).json({ message: 'ລຶບໂພສສຳເລັດແລ້ວ' });
  } else {
    res.status(404).json({ message: 'ບໍ່ພົບໂພສ' });
  }
});

app.listen(PORT, () => {
  console.log(`ເຊີບເວີກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${PORT}`);
});
```
ມັນຈະສົ່ງ 200 OK ຖ້າສຳເລັດ ຫຼື 404 Not Found ຖ້າບໍ່ພົບ. ງ່າຍໆແມ່ນບໍ່? ຢາກໃຫ້ເພີ່ມການກວດສອບສິດການເຂົ້າເຖິງບໍ່?

ແນ່ນອນ! Express middleware ແມ່ນດີເລີດສຳລັບສິ່ງນີ້. ນີ້ແມ່ນຕົວຢ່າງງ່າຍໆຂອງ middleware ເພື່ອກວດສອບຄີ API ກ່ອນເຂົ້າເຖິງ route:

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

const API_KEY = 'mysecretapikey'; // ຄີ API ຕົວຢ່າງ

// Middleware ສໍາລັບການກວດສອບ
const authenticate = (req, res, next) => {
  const apiKey = req.headers['x-api-key']; // ສົມມຸດວ່າຄີຢູ່ໃນ header 'x-api-key'
  if (apiKey && apiKey === API_KEY) {
    next(); // ໄປທີ່ route ຕໍ່ໄປ
  } else {
    res.status(401).json({ message: 'ບໍ່ໄດ້ຮັບອະນຸຍາດ: ຄີ API ບໍ່ຖືກຕ້ອງ' });
  }
};

// ນໍາໃຊ້ middleware ກັບ route ທີ່ຕ້ອງການ
app.get('/protected-data', authenticate, (req, res) => {
  res.json({ message: 'ນີ້ແມ່ນຂໍ້ມູນທີ່ໄດ້ຮັບການປົກປ້ອງ!', data: [1, 2, 3] });
});

app.get('/public-data', (req, res) => {
  res.json({ message: 'ນີ້ແມ່ນຂໍ້ມູນສາທາລະນະ.' });
});

app.listen(PORT, () => {
  console.log(`ເຊີບເວີກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${PORT}`);
});
```
