ได้เลยครับ นี่คือ `Avatar` component ที่มี fallback เป็นตัวอักษรย่อ:

```tsx
import React, { useState, HTMLAttributes } from 'react';

type AvatarProps = HTMLAttributes<HTMLDivElement> & {
  src?: string;
  alt: string;
  size?: number; // in pixels
};

const getInitials = (name: string) => {
  const parts = name.split(' ');
  if (parts.length === 1) return name.charAt(0).toUpperCase();
  return (parts[0].charAt(0) + parts[parts.length - 1].charAt(0)).toUpperCase();
};

export function Avatar({ src, alt, size = 48, style, ...rest }: AvatarProps) {
  const [imageError, setImageError] = useState(false);

  const avatarStyle: React.CSSProperties = {
    width: size,
    height: size,
    borderRadius: '50%',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#ccc',
    color: 'white',
    fontWeight: 'bold',
    fontSize: `${size / 3}px`,
    overflow: 'hidden',
    ...style,
  };

  if (src && !imageError) {
    return (
      <img
        src={src}
        alt={alt}
        onError={() => setImageError(true)}
        style={{ ...avatarStyle, objectFit: 'cover' }}
        {...rest}
      />
    );
  }

  return (
    <div style={avatarStyle} {...rest}>
      {getInitials(alt)}
    </div>
  );
}
```
ใช้งานง่ายๆ ครับ: `<Avatar src="user.jpg" alt="สมชาย ใจดี" />` หรือ `<Avatar alt="สมศรี มีสุข" />` (ถ้าไม่มีรูป)

