  return (
    <div
      style={{
        width: size,
        height: size,
        borderRadius: "50%",
        backgroundColor: "#ccc",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        overflow: "hidden",
        color: "#fff",
        fontSize: size * 0.4,
        fontWeight: "bold",
      }}
    >
      {showFallback ? (
        fallbackText || alt.charAt(0).toUpperCase()
      ) : (
        <img
          src={src}
          alt={alt}
          onError={() => setImgError(true)}
          style={{ width: "100%", height: "100%", objectFit: "cover" }}
        />
      )}
    </div>
  );
}
```
