Here's a basic `Toast` component for displaying temporary messages:

```tsx
import React, { ReactNode, useEffect, useState } from "react";

type Props = {
  message: ReactNode;
  duration?: number; // milliseconds
  onDismiss: () => void;
};

export function Toast({ message, duration = 3000, onDismiss }: Props) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (isVisible) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onDismiss();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [duration, onDismiss, isVisible]);

  if (!isVisible) return null;

  return (
    <div
      style={{
        position: "fixed",
        bottom: "20px",
        right: "20px",
        backgroundColor: "#333",
        color: "white",
        padding: "10px 20px",
        borderRadius: "5px",
        boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
        zIndex: 1000,
        opacity: isVisible ? 1 : 0,
        transition: "opacity 0.3s ease-in-out",
      }}
    >
      {message}
      <button onClick={onDismiss} style={{ marginLeft: "15px", background: "none", border: "none", color: "white", cursor: "pointer" }}>
        &times;
      </button>
    </div>
  );
}
```
You'd manage its `message` and `onDismiss` state from a parent. Would you like options for different types, like 'success' or 'error'?

