ได้ครับ Express จัดการ query parameters ได้ง่ายๆ เลย:

```javascript
import express from 'express';

const app = express();
const PORT = 3000;

// สมมติว่ามีข้อมูลสินค้าอยู่
const products = [
  { id: 1, name: 'Laptop', category: 'electronics', price: 1200 },
  { id: 2, name: 'Mouse', category: 'electronics', price: 25 },
  { id: 3, name: 'Notebook', category: 'stationery', price: 10 },
  { id: 4, name: 'Monitor', category: 'electronics', price: 300 }
];

app.get('/products', (req, res) => {
  let filteredProducts = [...products];

  const { category, min_price } = req.query;

  if (category) {
    filteredProducts = filteredProducts.filter(p => p.category === category);
  }

  if (min_price) {
    filteredProducts = filteredProducts.filter(p => p.price >= parseFloat(min_price));
  }

  res.json(filteredProducts);
});

app.listen(PORT, () => {
  console.log(`Server is running on http://localhost:${PORT}`);
});
```
