```tsx
import React, { useEffect, useState } from 'react';

interface ToastProps {
  message: string;
  duration?: number; // in milliseconds
  onClose?: () => void;
}

export function Toast({ message, duration = 3000, onClose }: ToastProps) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (isVisible) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onClose?.();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [isVisible, duration, onClose]);

  if (!isVisible) return null;

  return (
    <div style={{ position: 'fixed', bottom: '20px', left: '50%', transform: 'translateX(-50%)', background: '#333', color: 'white', padding: '10px 20px', borderRadius: '5px', zIndex: 1000 }}>
      {message}
    </div>
  );
}
```
Anda bisa menampilkannya dengan `useState` untuk `message` dan `onClose`. Ingin mendukung berbagai jenis notifikasi (sukses, error)?

