}

export function Select({ options, label, id, ...rest }: SelectProps) {
  const selectId = id || React.useId();
  return (
    <div>
      {label && <label htmlFor={selectId}>{label}</label>}
      <select id={selectId} {...rest}>
        {options.map((option) => (
          <option key={option.value} value={option.value}>
            {option.label}
          </option>
        ))}
      </select>
    </div>
  );
}
```
Contoh penggunaan: `<Select options={[{value: 'a', label: 'Opsi A'}]} onChange={handleSelection} />`. Apakah Anda membutuhkan dukungan untuk `optgroup`?

Tentu, ini komponen `Tabs` yang bisa Anda gunakan untuk mengatur konten:

```tsx
import React, { useState, ReactNode } from 'react';

interface TabItem {
  label: string;
  content: ReactNode;
}

interface TabsProps {
  tabs: TabItem[];
  initialActiveTab?: number;
}

export function Tabs({ tabs, initialActiveTab = 0 }: TabsProps) {
  const [activeTab, setActiveTab] = useState(initialActiveTab);

  return (
    <div>
      <div style={{ display: 'flex', borderBottom: '1px solid #ccc' }}>
        {tabs.map((tab, index) => (
          <button
            key={index}
            onClick={() => setActiveTab(index)}
            style={{
              padding: '10px 15px', border: 'none', background: 'transparent',
              cursor: 'pointer', fontWeight: index === activeTab ? 'bold' : 'normal',
              borderBottom: index === activeTab ? '2px solid blue' : 'none'
            }}
          >
            {tab.label}
          </button>
        ))}
      </div>
      <div style={{ padding: '15px 0' }}>
        {tabs[activeTab]?.content}
      </div>
    </div>
  );
}
```
Penggunaan: `<Tabs tabs={[{ label: 'Tab 1', content: <p>Konten Tab 1</p> }]} />`. Mudah disesuaikan, ya!

