Tentu, ini contoh endpoint GET sederhana dengan Express.js untuk daftar produk:

```javascript
const express = require('express');
const app = express();
const port = 3000;

const products = [
  { id: 1, name: 'Kopi Robusta', price: 25000 },
  { id: 2, name: 'Teh Hijau', price: 20000 },
  { id: 3, name: 'Cokelat Panas', price: 30000 },
];

app.get('/api/products', (req, res) => {
  res.json(products);
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Anda bisa menjalankan `node namafile.js` setelah `npm install express`. Apakah Anda butuh endpoint untuk detail produk berdasarkan ID?

Oke, ini cara membuat endpoint GET dengan Express.js untuk mencari produk berdasarkan ID:

```javascript
const express = require('express');
const app = express();
const port = 3000;

const products = [
  { id: 1, name: 'Kopi Robusta', price: 25000 },
  { id: 2, name: 'Teh Hijau', price: 20000 },
  { id: 3, name: 'Cokelat Panas', price: 30000 },
];

app.get('/api/products/:id', (req, res) => {
  const productId = parseInt(req.params.id);
  const product = products.find(p => p.id === productId);

  if (product) {
    res.json(product);
  } else {
    res.status(404).json({ message: 'Produk tidak ditemukan.' });
  }
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Anda bisa mencoba mengakses `/api/products/1`. Perlu bantuan untuk menambahkan fitur edit produk?

Tentu, ini endpoint DELETE di Express.js untuk menghapus buku berdasarkan ID:

```javascript
const express = require('express');
const app = express();
const port = 3000;

let books = [
  { id: 1, title: 'Bumi Manusia', author: 'Pramoedya Ananta Toer' },
  { id: 2, title: 'Laskar Pelangi', author: 'Andrea Hirata' },
  { id: 3, title: 'Filosofi Kopi', author: 'Dewi Lestari' },
];

app.delete('/api/books/:id', (req, res) => {
  const bookId = parseInt(req.params.id);
  const initialLength = books.length;
  books = books.filter(b => b.id !== bookId);

  if (books.length < initialLength) {
    res.status(200).json({ message: `Buku dengan ID ${bookId} berhasil dihapus.` });
  } else {
    res.status(404).json({ message: 'Buku tidak ditemukan.' });
  }
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Anda bisa menguji dengan permintaan DELETE ke `/api/books/1`. Semoga berhasil!

Tentu, ini contoh file Express.js dengan endpoint GET dan POST untuk mengelola daftar tugas:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // Untuk membaca body JSON

let tasks = [
  { id: 1, description: 'Belajar Express.js', completed: false },
  { id: 2, description: 'Menyelesaikan tugas kuliah', completed: true },
];
let nextId = 3;

// Endpoint untuk mendapatkan semua tugas
app.get('/api/tasks', (req, res) => {
  res.json(tasks);
});

// Endpoint untuk menambah tugas baru
app.post('/api/tasks', (req, res) => {
  const { description } = req.body;
  if (!description) {
    return res.status(400).json({ message: 'Deskripsi tugas diperlukan.' });
  }
  const newTask = { id: nextId++, description, completed: false };
  tasks.push(newTask);
  res.status(201).json({ message: 'Tugas berhasil ditambahkan!', task: newTask });
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Anda sekarang punya API sederhana untuk daftar tugas! Butuh endpoint untuk memperbarui atau menghapus tugas?

