Narito ang isang `ToggleSwitch` na may panloob na estado at `onChange` callback:

```tsx
import React, { useState } from 'react';

type ToggleSwitchProps = {
  initialChecked?: boolean;
  onChange?: (checked: boolean) => void;
  label?: string;
};

export function ToggleSwitch({ initialChecked = false, onChange, label }: ToggleSwitchProps) {
  const [isChecked, setIsChecked] = useState(initialChecked);

  const handleToggle = () => {
    const newState = !isChecked;
    setIsChecked(newState);
    onChange?.(newState);
  };

  return (
    <label style={{ display: 'inline-flex', alignItems: 'center', cursor: 'pointer' }}>
      {label && <span style={{ marginRight: '8px' }}>{label}</span>}
      <input
        type="checkbox"
        checked={isChecked}
        onChange={handleToggle}
        style={{ position: 'absolute', opacity: 0, width: 0, height: 0 }}
      />
      <span
        style={{
          width: '40px',
          height: '24px',
          borderRadius: '12px',
          backgroundColor: isChecked ? '#4CAF50' : '#ccc',
          position: 'relative',
          transition: 'background-color 0.2s',
          display: 'inline-block',
        }}
      >
        <span
          style={{
            position: 'absolute',
            left: isChecked ? 'calc(100% - 20px)' : '4px',
            top: '2px',
            width: '20px',
            height: '20px',
            borderRadius: '50%',
            backgroundColor: 'white',
            transition: 'left 0.2s',
          }}
        />
      </span>
    </label>
  );
}
```
Gamitin ito: `<ToggleSwitch label="Enable Feature" onChange={checked => console.log(checked)} />`. Mas gusto mo ba ng Tailwind CSS para sa styling?

