      <input
        type="checkbox"
        id={switchId}
        checked={isChecked}
        onChange={handleToggle}
        style={{ display: 'none' }} // Sembunyikan input asal
        {...rest}
      />
      <label
        htmlFor={switchId}
        style={{
          cursor: 'pointer',
          width: '40px',
          height: '20px',
