Baik, ini komponen `Toast` yang ringkas, akan hilang selepas beberapa saat:

```tsx
import React, { useEffect, useState, ReactNode } from 'react';

type ToastProps = {
  message: ReactNode;
  duration?: number; // dalam milisaat
  onClose?: () => void;
  type?: 'success' | 'error' | 'info';
};

const typeColors = {
  success: '#4CAF50',
  error: '#f44336',
  info: '#2196F3',
};

export function Toast({ message, duration = 3000, onClose, type = 'info' }: ToastProps) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (isVisible) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onClose?.();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [isVisible, duration, onClose]);

  if (!isVisible) return null;

  return (
    <div
      style={{
        position: 'fixed',
        bottom: '20px',
        right: '20px',
        backgroundColor: typeColors[type] || typeColors.info,
        color: 'white',
        padding: '15px 20px',
        borderRadius: '5px',
        boxShadow: '0 4px 8px rgba(0,0,0,0.2)',
        zIndex: 1000,
        display: 'flex',
        alignItems: 'center',
        gap: '10px'
      }}
    >
      {message}
      <button
        onClick={() => {
          setIsVisible(false);
          onClose?.();
        }}
        style={{
          background: 'none',
          border: 'none',
          color: 'white',
          fontSize: '1.2em',
          cursor: 'pointer'
        }}
      >
        &times;
      </button>
    </div>
  );
}
```
Anda boleh panggil dengan `<Toast message="Data berjaya disimpan!" type="success" />`. Mahu ia muncul dari atas atau tengah skrin?

