ບັນທຶກເປັນ `app.js`, ຕິດຕັ້ງ `express` (`npm i express`), ແລ້ວແລ່ນດ້ວຍ `node app.js` ເດີ້.

ໄດ້ເລີຍ, ນີ້ແມ່ນ Express endpoint ສຳລັບສ້າງຜູ້ໃຊ້ໃໝ່ແບບ POST, ພ້ອມໃຊ້ body parser ເດີ້:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // ສຳລັບ parse JSON request bodies

let users = []; // ແທນຖານຂໍ້ມູນງ່າຍໆ

app.post('/users', (req, res) => {
