  }
  const newUser = { id: users.length + 1, name, email };
  users.push(newUser);
  res.status(201).json(newUser);
});

app.listen(port, () => {
  console.log(`Server ກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${port}`);
});
```
ທ່ານສາມາດທົດສອບດ້ວຍ Postman ຫຼື curl ໂດຍການສົ່ງ JSON body ເດີ້.

ໄດ້ເລີຍ, ນີ້ແມ່ນ Express endpoint ສຳລັບລຶບລາຍການໂດຍໃຊ້ ID:

```javascript
const express = require('express');
const app = express();
const port = 3000;

let items = [
  { id: 1, name: 'ໝາກໄມ້' },
  { id: 2, name: 'ຜັກ' },
  { id: 3, name: 'ຊີ້ນ' }
];

app.delete('/items/:id', (req, res) => {
  const itemId = parseInt(req.params.id);
  const initialLength = items.length;
  items = items.filter(item => item.id !== itemId);

  if (items.length < initialLength) {
    res.status(200).send(`ລາຍການ ID ${itemId} ຖືກລຶບແລ້ວ.`);
  } else {
    res.status(404).send(`ບໍ່ພົບລາຍການ ID ${itemId}.`);
  }
});

app.listen(port, () => {
  console.log(`Server ກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${port}`);
});
```
ທ່ານສາມາດທົດສອບດ້ວຍການສົ່ງ DELETE request ໄປທີ່ `/items/1` ເດີ້.

ໄດ້ເລີຍ, ນີ້ແມ່ນ Express endpoint ທີ່ຮອງຮັບການ filter ດ້ວຍ query parameters:

```javascript
const express = require('express');
const app = express();
const port = 3000;

const products = [
  { id: 1, name: 'ເສື້ອ', category: 'ເຄື່ອງນຸ່ງ', price: 150 },
  { id: 2, name: 'ເກີບ', category: 'ເຄື່ອງນຸ່ງ', price: 250 },
  { id: 3, name: 'ປຶ້ມ', category: 'ເຄື່ອງຂຽນ', price: 50 },
  { id: 4, name: 'ໂຕະ', category: 'ເຄື່ອງເຮືອນ', price: 300 }
];

app.get('/products', (req, res) => {
  let filteredProducts = [...products];
  const { category, min_price } = req.query;

  if (category) {
    filteredProducts = filteredProducts.filter(p => p.category === category);
  }
  if (min_price) {
    filteredProducts = filteredProducts.filter(p => p.price >= parseFloat(min_price));
  }

  res.json(filteredProducts);
});

app.listen(port, () => {
  console.log(`Server ກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${port}`);
});
```
ທ່ານສາມາດທົດສອບໂດຍການເຂົ້າເຖິງ URL ທີ່ມີ query parameters ເດີ້.

