Certainly! Adding error handling is crucial. Here's how you can implement a basic error middleware in Express:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // For parsing application/json

app.get('/risky-operation', (req, res, next) => {
  try {
    // Simulate an operation that might fail
    if (Math.random() > 0.5) {
      throw new Error('Something went wrong during operation!');
    }
    res.send('Operation successful!');
  } catch (error) {
    next(error); // Pass error to the error handling middleware
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack); // Log the error for debugging
  res.status(500).send('An internal server error occurred!');
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});
```
This catches errors and sends a friendly 500 response. Would you like to explore more specific error types?

