ရပါပြီခင်ဗျာ။ Express နဲ့ ကုန်ပစ္စည်းစာရင်းကို ပြန်ပေးမယ့် GET endpoint လေးပါ။

```javascript
const express = require('express');
const app = express();
const port = 3000;

// ဥပမာ ကုန်ပစ္စည်းဒေတာ
const products = [
  { id: 1, name: 'Laptop', price: 1200 },
  { id: 2, name: 'Mouse', price: 25 },
  { id: 3, name: 'Keyboard', price: 75 }
];

app.get('/products', (req, res) => {
  res.json(products);
});

app.listen(port, () => {
  console.log(`Server is running on http://localhost:${port}`);
});
```
ဒီ code ကို `server.js` လို့ သိမ်းပြီး `node server.js` နဲ့ run လို့ရပါတယ်။ လိုအပ်ရင် ဒေတာဘေ့စ်နဲ့ ချိတ်ဆက်ဖို့လည်း ကူညီပေးနိုင်ပါတယ်။

ရပါပြီခင်ဗျာ။ Express နဲ့ `book` အသစ်ထည့်သွင်းဖို့ POST endpoint လေးပါ။

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // JSON request body တွေကို parse လုပ်ဖို့

let books = [
  { id: 1, title: 'The Great Gatsby', author: 'F. Scott Fitzgerald' }
];

app.post('/books', (req, res) => {
  const newBook = { id: books.length + 1, ...req.body };
  books.push(newBook);
  res.status(201).json(newBook);
});

app.listen(port, () => {
  console.log(`Server is running on http://localhost:${port}`);
});
```
ဒီ endpoint ကို Postman ဒါမှမဟုတ် Insomnia လို tool တွေနဲ့ စမ်းသပ်နိုင်ပါတယ်။ body မှာ `{"title": "New Book", "author": "Author Name"}` လိုမျိုး ထည့်ပေးရမှာပါ။

ရပါပြီခင်ဗျာ။ Express မှာ ID နဲ့ သုံးစွဲသူတစ်ယောက်ကို ရယူနိုင်မယ့် GET endpoint လေးပါ။

```javascript
const express = require('express');
const app = express();
const port = 3000;

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
  { id: 3, name: 'Charlie' }
];

app.get('/users/:id', (req, res) => {
  const userId = parseInt(req.params.id);
  const user = users.find(u => u.id === userId);
  if (user) {
    res.json(user);
  } else {
    res.status(404).send('User not found');
  }
});

app.listen(port, () => {
  console.log(`Server is running on http://localhost:${port}`);
});
```
ဒီ endpoint ကို `http://localhost:3000/users/1` လိုမျိုး ခေါ်နိုင်ပါတယ်။

ရပါပြီခင်ဗျာ။ Express နဲ့ `order` တစ်ခုကို ဖျက်ပစ်နိုင်မယ့် DELETE endpoint လေးပါ။

```javascript
const express = require('express');
const app = express();
const port = 3000;

let orders = [
  { id: 101, item: 'Coffee', quantity: 2 },
  { id: 102, item: 'Tea', quantity: 1 }
];

app.delete('/orders/:id', (req, res) => {
  const orderId = parseInt(req.params.id);
  const initialLength = orders.length;
  orders = orders.filter(o => o.id !== orderId);

  if (orders.length < initialLength) {
    res.status(200).send(`Order with ID ${orderId} deleted.`);
  } else {
    res.status(404).send('Order not found');
  }
});

app.listen(port, () => {
  console.log(`Server is running on http://localhost:${port}`);
});
```
ဒီ endpoint ကို `http://localhost:3000/orders/101` လိုမျိုး DELETE request ပို့ပြီး စမ်းသပ်နိုင်ပါတယ်။

