បានការ! នេះជា Toast component ដ៏សាមញ្ញសម្រាប់បង្ហាញសារជូនដំណឹង៖

```tsx
import React, { useEffect, useState } from 'react';

interface ToastProps {
  message: string;
  duration?: number; // in milliseconds
  onClose?: () => void;
}

export const Toast: React.FC<ToastProps> = ({ message, duration = 3000, onClose }) => {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsVisible(false);
      onClose?.();
    }, duration);
    return () => clearTimeout(timer);
  }, [duration, onClose]);

  if (!isVisible) return null;

  return (
    <div
      style={{
        position: 'fixed',
        bottom: '20px',
        left: '50%',
        transform: 'translateX(-50%)',
        backgroundColor: '#333',
        color: 'white',
        padding: '10px 20px',
        borderRadius: '5px',
        zIndex: 9999,
        opacity: isVisible ? 1 : 0,
        transition: 'opacity 0.3s ease-in-out',
      }}
    >
      {message}
    </div>
  );
};
```
អ្នកអាចបង្ហាញវាដោយកំណត់ `message` prop។ វាបាត់ទៅវិញដោយខ្លួនឯងបន្ទាប់ពី `duration`។

