Tuyệt vời! Dưới đây là component Toast Message có thể tự động đóng:

```tsx
import React, { useState, useEffect } from 'react';

type ToastProps = {
  message: string;
  type?: 'success' | 'error' | 'info';
  duration?: number; // milliseconds
  onClose?: () => void;
};

export function Toast({ message, type = 'info', duration = 3000, onClose }: ToastProps) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (!isVisible) return;
    const timer = setTimeout(() => {
      setIsVisible(false);
      onClose?.();
    }, duration);
    return () => clearTimeout(timer);
  }, [duration, isVisible, onClose]);

  if (!isVisible) return null;

  const bgColor = type === 'success' ? '#4CAF50' : type === 'error' ? '#F44336' : '#2196F3';

  return (
    <div
      style={{
        padding: '12px 20px', borderRadius: '4px', color: 'white',
        backgroundColor: bgColor, position: 'fixed', bottom: '20px', left: '50%',
        transform: 'translateX(-50%)', zIndex: 9999, boxShadow: '0 2px 10px rgba(0,0,0,0.2)'
      }}
    >
      {message}
      <button
        onClick={() => { setIsVisible(false); onClose?.(); }}
        style={{ marginLeft: '10px', background: 'none', border: 'none', color: 'white', cursor: 'pointer' }}
      >X</button>
    </div>
  );
}
