```tsx
import React, { useState, useEffect, ReactNode } from 'react';

type ToastProps = {
  message: ReactNode;
  duration?: number; // milliseconds
  onClose?: () => void;
};

export function Toast({ message, duration = 3000, onClose }: ToastProps) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (isVisible) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onClose?.();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [duration, isVisible, onClose]);

  if (!isVisible) return null;

  return (
    <div
      style={{
        position: 'fixed', bottom: '20px', left: '50%', transform: 'translateX(-50%)',
        backgroundColor: '#333', color: 'white', padding: '12px 20px',
        borderRadius: '8px', zIndex: 1001, boxShadow: '0 2px 10px rgba(0,0,0,0.2)',
        opacity: isVisible ? 1 : 0, transition: 'opacity 0.5s ease-in-out'
      }}
    >
      {message}
    </div>
  );
}
```
အသုံးပြုပုံ: ` <Toast message="အချက်အလက်များ သိမ်းဆည်းပြီးပါပြီ!" duration={2500} />` ပါ။

