```python
import csv

def filter_low_stock(file_path: str, stock_limit: int = 10):
    try:
        with open(file_path, newline='', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            print(f"Các sản phẩm có tồn kho dưới {stock_limit}:")
            found_items = False
            for row in reader:
                try:
                    if int(row['so_luong_ton_kho']) < stock_limit:
                        print(f"  - {row['ten_san_pham']} (ID: {row['ma_san_pham']}, Tồn kho: {row['so_luong_ton_kho']})")
                        found_items = True
                except (ValueError, KeyError):
                    continue # Bỏ qua các hàng lỗi hoặc thiếu cột
            if not found_items:
                print("  Không tìm thấy sản phẩm nào.")
    except FileNotFoundError:
        print(f"Lỗi: Không tìm thấy file tại đường dẫn '{file_path}'.")

if __name__ == "__main__":
    # Giả sử bạn có một file 'products.csv' với các cột 'ma_san_pham', 'ten_san_pham', 'so_luong_ton_kho'
    filter_low_stock('products.csv')
