```python
import requests
from bs4 import BeautifulSoup

def get_website_title(url: str) -> str | None:
    try:
        response = requests.get(url, timeout=5) # Thêm timeout để tránh kẹt
        response.raise_for_status() # Ném lỗi cho các mã trạng thái HTTP không thành công
        soup = BeautifulSoup(response.text, 'html.parser')
        title_tag = soup.find('title')
        if title_tag:
            return title_tag.get_text(strip=True)
        else:
            return "Không tìm thấy tiêu đề"
    except requests.exceptions.RequestException as e:
        print(f"Lỗi khi truy cập URL '{url}': {e}")
        return None
    except Exception as e:
        print(f"Đã xảy ra lỗi: {e}")
        return None

if __name__ == "__main__":
    target_url = "https://www.rnai.io"
    title = get_website_title(target_url)
    if title:
        print(f"Tiêu đề của trang '{target_url}' là: {title}")
    else:
        print(f"Không thể lấy tiêu đề từ '{target_url}'.")
```
