```tsx
import React, { useEffect, useState } from 'react';

interface ToastProps {
  message: string;
  duration?: number; // in milliseconds
  onClose: () => void;
}

export const Toast: React.FC<ToastProps> = ({ message, duration = 3000, onClose }) => {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsVisible(false);
      onClose();
    }, duration);
    return () => clearTimeout(timer);
  }, [duration, onClose]);

  if (!isVisible) return null;

  return (
    <div style={{
      position: 'fixed', bottom: '20px', right: '20px',
      background: '#333', color: '#fff', padding: '12px 20px',
      borderRadius: '8px', boxShadow: '0 4px 8px rgba(0,0,0,0.2)',
      zIndex: 1001, opacity: isVisible ? 1 : 0, transition: 'opacity 0.3s'
    }}>
      {message}
    </div>
  );
};
```
Untuk menggunakannya, anda perlu menguruskan `isVisible` di parent component dan panggil `onClose`. Nak tambahkan jenis notifikasi (success/error)?

