```php
<?php

function countWorkingDays(string $startDate, string $endDate): int {
    $start = new DateTime($startDate);
    $end = new DateTime($endDate);
    $workingDays = 0;

    // Ubah tarikh akhir untuk memasukkan hari terakhir jika ia hari bekerja
    $end->modify('+1 day'); 

    while ($start < $end) {
        $dayOfWeek = (int)$start->format('N'); // 1 (Isnin) hingga 7 (Ahad)
        if ($dayOfWeek >= 1 && $dayOfWeek <= 5) { // Isnin-Jumaat
            $workingDays++;
        }
        $start->modify('+1 day');
    }
    return $workingDays;
}

// Contoh penggunaan
echo countWorkingDays('2023-10-01', '2023-10-31'); // Output: 22 (hari bekerja dalam Okt 2023)
echo "\n";
echo countWorkingDays('2023-12-23', '2023-12-26'); // Output: 2 (25 & 26 Disember)

?>
```
