Pasti, ini fungsi C# untuk mengesan palindrom:

```csharp
using System;
using System.Linq;

public class PalindromeChecker
{
    public static bool IsPalindrome(string word)
    {
        if (string.IsNullOrEmpty(word))
        {
            return false;
        }
        // Buang aksara bukan huruf/nombor dan tukar kepada huruf kecil
        string cleanedWord = new string(word.Where(char.IsLetterOrDigit).ToArray()).ToLower();
        string reversedWord = new string(cleanedWord.Reverse().ToArray());
        return cleanedWord.Equals(reversedWord);
    }

    public static void Main(string[] args)
    {
        Console.WriteLine(IsPalindrome("madam"));      // Output: True
        Console.WriteLine(IsPalindrome("Level"));      // Output: True
        Console.WriteLine(IsPalindrome("Hello"));      // Output: False
        Console.WriteLine(IsPalindrome("A man, a plan, a canal: Panama")); // Output: True
    }
}
```
