Ini endpoint PUT di Express.js untuk memperbarui profil pengguna:

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

app.use(express.json());

let users = [
  { id: 1, name: 'Budi', email: 'budi@example.com' },
  { id: 2, name: 'Siti', email: 'siti@example.com' }
];

app.put('/users/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const { name, email } = req.body;
  const userIndex = users.findIndex(u => u.id === id);

  if (userIndex === -1) {
    return res.status(404).json({ message: 'Pengguna tidak ditemukan' });
  }

  users[userIndex] = { ...users[userIndex], name: name || users[userIndex].name, email: email || users[userIndex].email };
  res.json(users[userIndex]);
});

app.listen(PORT, () => {
  console.log(`Server berjalan di http://localhost:${PORT}`);
});
```
Anda bisa mengirim PUT request ke `http://localhost:3000/users/1` dengan body `{ "name": "Budi Santoso" }`. Selamat mencoba!

