```csharp
using System;

public class MathUtils
{
    public static long CalculateFactorial(int n)
    {
        if (n < 0)
        {
            throw new ArgumentOutOfRangeException("n", "Factorial is not defined for negative numbers.");
        }
        if (n == 0)
        {
            return 1;
        }

        long result = 1;
        for (int i = 1; i <= n; i++)
        {
            result *= i;
        }
        return result;
    }

    // Halimbawa ng Paggamit:
    public static void Main(string[] args)
    {
        Console.WriteLine($"Factorial of 5 is: {CalculateFactorial(5)}");   // Output: 120
        Console.WriteLine($"Factorial of 0 is: {CalculateFactorial(0)}");   // Output: 1
        // Console.WriteLine(CalculateFactorial(-1)); // Ito ay magta-throw ng exception
    }
}
```
Gumagamit ito ng `long` para masuportahan ang mas malalaking numero. Simple lang, di ba? :)

