```javascript
const express = require('express');
const app = express();
const port = 3000;

// Contoh endpoint
app.get('/', (req, res) => {
  res.send('Selamat datang ke API saya!');
});

// Middleware untuk pengendalian ralat 404 (Not Found)
app.use((req, res, next) => {
  res.status(404).send('Maaf, laluan tidak ditemui!');
});

// Middleware untuk pengendalian ralat generik
app.use((err, req, res, next) => {
  console.error(err.stack); // Log ralat ke konsol
  res.status(500).send('Ada sesuatu yang tidak kena di server!');
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Pastikan middleware 404 diletakkan selepas semua laluan anda, dan middleware ralat generik diletakkan paling akhir. Ini akan menangani sebarang laluan yang tidak sepadan atau ralat yang berlaku.

