```javascript
const path = require('path');

function hasAllowedExtension(filename, allowedExtensions) {
  // Ensure extensions are lowercased for case-insensitive comparison
  const fileExtension = path.extname(filename).toLowerCase();
  const lowercasedAllowed = allowedExtensions.map(ext => ext.toLowerCase());

  return lowercasedAllowed.includes(fileExtension);
}

// Example usage:
const allowedImageExtensions = ['.jpg', '.jpeg', '.png', '.gif'];
console.log(hasAllowedExtension('image.jpg', allowedImageExtensions));  // true
console.log(hasAllowedExtension('document.pdf', allowedImageExtensions)); // false
console.log(hasAllowedExtension('photo.PNG', allowedImageExtensions));  // true (case-insensitive)
```
