import { useState } from 'react';

type StarRatingProps = {
  totalStars?: number;
  initialRating?: number;
  onRatingChange?: (rating: number) => void;
};

export function StarRating({
  totalStars = 5,
  initialRating = 0,
  onRatingChange,
}: StarRatingProps) {
