Para sa basic error handling sa Express.js, pwede kang gumamit ng middleware. Narito ang isang halimbawa:

```javascript
const express = require('express');
const app = express();
const port = 3000;

// Sample data
const users = [{ id: 1, name: 'Anna' }, { id: 2, name: 'Ben' }];

app.get('/users/:id', (req, res, next) => {
  const id = parseInt(req.params.id);
  const user = users.find(u => u.id === id);

  if (user) {
    res.json(user);
  } else {
    // Ipasa sa error handling middleware
    const error = new Error('User not found');
    error.status = 404;
    next(error);
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(err.status || 500).json({
    error: {
      message: err.message || 'Something went wrong',
      status: err.status || 500
    }
  });
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});
```
Ang `next(error)` ang magpapasa ng error sa middleware na may apat na parameter. Ito ay very useful para sa centralisadong error management. Malaking tulong ito para maging matatag ang API mo!

