```javascript
const express = require('express');
const app = express();
const port = 3000;

app.get('/risky-operation', (req, res, next) => {
  try {
    // Contoh operasi yang mungkin gagal
    if (Math.random() > 0.5) {
      throw new Error('Sesuatu telah berlaku!');
    }
    res.send('Operasi berjaya.');
  } catch (error) {
    next(error); // Hantar ralat ke middleware pengendalian ralat
  }
});

// Middleware pengendalian ralat
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).send('Ada masalah pada server kami!');
});

app.listen(port, () => {
  console.log(`Server berjalan di http://localhost:${port}`);
});
```
Middleware `app.use((err, req, res, next) => {...})` akan menangani sebarang ralat yang dilemparkan. Ingin tahu lebih lanjut tentang jenis ralat?

