បាន! នេះជា function C# សម្រាប់ពិនិត្យមើល palindrome ដោយមិនគិតពីអក្សរធំតូច:

```csharp
using System;
using System.Linq;

public class StringUtilities
{
    public static bool IsPalindrome(string text)
    {
        if (string.IsNullOrEmpty(text))
            return true;

        // Remove non-alphanumeric characters and convert to lowercase
        string cleanedText = new string(text.Where(char.IsLetterOrDigit).ToArray()).ToLower();
        string reversedText = new string(cleanedText.Reverse().ToArray());
        return cleanedText.Equals(reversedText);
    }
}

// ឧទាហរណ៍ការប្រើប្រាស់:
// Console.WriteLine(StringUtilities.IsPalindrome("madam")); // True
// Console.WriteLine(StringUtilities.IsPalindrome("A man, a plan, a canal: Panama")); // True
// Console.WriteLine(StringUtilities.IsPalindrome("hello")); // False
```
