```javascript
function formatKhmerPhoneNumber(phoneNumber) {
  if (!phoneNumber) {
    return "";
  }
  const cleaned = phoneNumber.replace(/\D/g, ''); // Remove non-digits

  if (cleaned.length === 9) { // Example: 012345678
    return `${cleaned.substring(0, 3)} ${cleaned.substring(3, 6)} ${cleaned.substring(6, 9)}`;
  }
  if (cleaned.length === 10) { // Example: 0123456789
    return `${cleaned.substring(0, 3)} ${cleaned.substring(3, 6)} ${cleaned.substring(6, 10)}`;
  }
  return phoneNumber; // Return original if not 9 or 10 digits
}

// ឧទាហរណ៍ការប្រើប្រាស់:
// console.log(formatKhmerPhoneNumber("012345678"));   // "012 345 678"
// console.log(formatKhmerPhoneNumber("0987654321"));  // "098 765 4321"
// console.log(formatKhmerPhoneNumber("123"));         // "123"
```
