Boleh sangat! Berikut adalah skrip Python untuk menggabungkan dua fail CSV berdasarkan ID umum:

```python
import csv

def merge_csv_files(file1_path: str, file2_path: str, output_path: str, join_column: str):
    data1 = {}
    fieldnames1 = []
    with open(file1_path, 'r', newline='', encoding='utf-8') as f1:
        reader1 = csv.DictReader(f1)
        fieldnames1 = reader1.fieldnames
        for row in reader1:
            data1[row[join_column]] = row

    fieldnames2 = []
    merged_rows = []
    with open(file2_path, 'r', newline='', encoding='utf-8') as f2:
        reader2 = csv.DictReader(f2)
        fieldnames2 = reader2.fieldnames

        combined_fieldnames = list(fieldnames1)
        for fn in fieldnames2:
            if fn not in combined_fieldnames:
                combined_fieldnames.append(fn)

        for row2 in reader2:
            id_val = row2.get(join_column)
            if id_val in data1:
                merged_row = {**data1[id_val], **row2}
                merged_rows.append(merged_row)

    with open(output_path, 'w', newline='', encoding='utf-8') as outfile:
        writer = csv.DictWriter(outfile, fieldnames=combined_fieldnames)
        writer.writeheader()
        for row in merged_rows:
            clean_row = {k: row.get(k, '') for k in combined_fieldnames}
            writer.writerow(clean_row)

if __name__ == "__main__":
    merge_csv_files("produk.csv", "harga.csv", "produk_lengkap.csv", "id_produk")
    print("Fail 'produk_lengkap.csv' telah berjaya dihasilkan dengan data yang digabungkan.")
```
Skrip ini akan mengambil semua lajur dari kedua-dua fail. Adakah anda ingin menguruskan kes di mana ID tidak ditemui dalam salah satu fail?

