```javascript
import express from 'express';

const app = express();
const port = 3000;

let items = [
  { id: 1, name: 'ສໍດໍາ' },
  { id: 2, name: 'ປື້ມ' },
  { id: 3, name: 'ຢາງລຶບ' }
];

app.delete('/items/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const initialLength = items.length;
  items = items.filter(item => item.id !== id);

  if (items.length < initialLength) {
    res.status(200).send(`Item with ID ${id} deleted.`);
  } else {
    res.status(404).send('Item not found.');
  }
});

app.listen(port, () => {
  console.log(`Server ກຳລັງແລ່ນຢູ່ທີ່ http://localhost:${port}`);
});
```
ທ່ານສາມາດສົ່ງ request DELETE ໄປທີ່ `/items/2` ເພື່ອລຶບລາຍການທີ່ມີ ID ເທົ່າກັບ 2. ມີຫຍັງອີກທີ່ຂ້ອຍຊ່ວຍໄດ້ບໍ່?

