```javascript
const express = require('express');
const app = express();
const port = 3000;

let posts = [
  { id: 1, title: 'Bài viết 1' },
  { id: 2, title: 'Bài viết 2' },
  { id: 3, title: 'Bài viết 3' }
];

app.delete('/posts/:id', (req, res) => {
  const postId = parseInt(req.params.id);
  const initialLength = posts.length;
  posts = posts.filter(post => post.id !== postId);

  if (posts.length < initialLength) {
    res.status(200).json({ message: 'Bài viết đã xóa thành công.' });
  } else {
    res.status(404).json({ message: 'Không tìm thấy bài viết.' });
  }
});

app.listen(port, () => {
  console.log(`Server chạy tại http://localhost:${port}`);
});
```
Gọi `DELETE /posts/2` để xóa bài viết có ID là 2. Có cần thêm xác nhận trước khi xóa không ạ?

