Here's a clear TypeScript function to determine if a date string is in the future:

```typescript
function isFutureDate(dateString: string): boolean {
  const inputDate = new Date(dateString);
  const now = new Date();

  // Clear time components for comparison if only date matters
  inputDate.setHours(0, 0, 0, 0);
  now.setHours(0, 0, 0, 0);

  return inputDate.getTime() > now.getTime();
}

// Example usage:
console.log(isFutureDate('2025-01-15')); // true (assuming today is before 2025-01-15)
console.log(isFutureDate('2023-01-01')); // false (assuming today is after 2023-01-01)
console.log(isFutureDate('2024-07-20')); // true or false, depending on current date
```
