แน่นอนครับ นี่คือโครงสร้างของคอมโพเนนต์ `Tabs` และ `Tab` ที่คุณสามารถใช้สร้าง UI แบบแท็บได้:

```tsx
import React, { useState, ReactNode } from 'react';

type TabProps = {
  label: string;
  children: ReactNode;
};

export function Tab({ children }: TabProps) {
  return <div>{children}</div>;
}

type TabsProps = {
  children: React.ReactElement<TabProps>[];
};

export function Tabs({ children }: TabsProps) {
  const [activeTab, setActiveTab] = useState(0);

  return (
    <div>
      <div style={{ borderBottom: '1px solid #ccc', display: 'flex' }}>
        {React.Children.map(children, (child, index) => {
          if (!React.isValidElement<TabProps>(child)) return null;
          return (
            <button
              key={index}
              onClick={() => setActiveTab(index)}
              style={{
                padding: '10px 15px', border: 'none', background: 'transparent', cursor: 'pointer',
                borderBottom: index === activeTab ? '2px solid #007bff' : 'none',
                color: index === activeTab ? '#007bff' : '#333'
              }}
            >
              {child.props.label}
            </button>
          );
        })}
      </div>
      <div style={{ paddingTop: '20px' }}>
        {React.Children.map(children, (child, index) => (
          index === activeTab ? child : null
        ))}
      </div>
    </div>
  );
}
```
ใช้งานแบบนี้ได้เลยครับ:
