import React, { useState } from 'react';

function MyComponent() {
  const [showModal, setShowModal] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [hasError, setHasError] = useState(false);

  // ...
}
```

Chào bạn! Bạn hoàn toàn có thể nhóm các trạng thái liên quan này vào một đối tượng `useState` duy nhất để quản lý gọn gàng hơn nhé:

```javascript
import React, { useState } from 'react';

function MyComponent() {
  const [uiState, setUiState] = useState({
    showModal: false,
    isLoading: false,
    hasError: false,
  });

  // Để cập nhật: setUiState(prev => ({ ...prev, showModal: true }));
  // ...
}
```
Cách này giúp bạn quản lý trạng thái tập trung hơn. Nhớ dùng spread operator (`...prev`) khi cập nhật để không làm mất các giá trị khác nhé!

