Pasti, ini fungsi Go untuk menjana slug URL:

```go
package main

import (
	"fmt"
	"regexp"
	"strings"
)

func GenerateSlug(s string) string {
	// Tukar ke huruf kecil
	lower := strings.ToLower(s)

	// Gantikan aksara bukan huruf/angka/ruang dengan ruang
	re := regexp.MustCompile(`[^a-z0-9\s-]`)
	cleaned := re.ReplaceAllString(lower, " ")

	// Gantikan berbilang ruang/sempang dengan satu sempang
	re = regexp.MustCompile(`[\s-]+`)
	slug := re.ReplaceAllString(cleaned, "-")

	// Buang sempang di awal/akhir
	return strings.Trim(slug, "-")
}

func main() {
	fmt.Println(GenerateSlug("Tajuk Artikel Yang Menarik!")) // tajuk-artikel-yang-menarik
	fmt.Println(GenerateSlug("Another Article Title with Spécîal Chars")) // another-article-title-with-special-chars
}
```
Fungsi ini akan menukar ke huruf kecil, membuang aksara khas, dan menggantikan ruang dengan sempang. Bagaimana?

