Narito ang Express endpoint na kailangan mo para kumuha ng isang produkto gamit ang ID nito:

```javascript
const express = require('express');
const app = express();

const products = [
  { id: 101, name: 'Smartphone', price: 25000 },
  { id: 102, name: 'Smartwatch', price: 8000 }
];

app.get('/api/products/:id', (req, res) => {
