  const product = products.find(p => p.id === productId);

  if (product) {
    res.json(product);
  } else {
    res.status(404).send('Product not found');
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```
I-try mo sa `http://localhost:3000/api/products/101`. Gusto mo bang magdagdag ng error handling para sa invalid ID format?

Okey, narito ang isang Express.js DELETE endpoint para magtanggal ng user gamit ang kanilang ID:

```javascript
const express = require('express');
const app = express();
app.use(express.json());

let users = [
  { id: 1, name: 'Juan Dela Cruz' },
  { id: 2, name: 'Maria Clara' },
  { id: 3, name: 'Crisostomo Ibarra' }
];

app.delete('/api/users/:id', (req, res) => {
  const userId = parseInt(req.params.id);
  const initialLength = users.length;
  users = users.filter(user => user.id !== userId);

  if (users.length < initialLength) {
    res.status(200).send(`User with ID ${userId} deleted.`);
  } else {
    res.status(404).send('User not found.');
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```
Magpadala ka lang ng DELETE request sa `http://localhost:3000/api/users/2`. Maligaya ka na ba rito?

