**โค้ดเดิม (ตัวอย่าง):**
```go
package main

import "fmt"

func createMap() map[string]int {
	counts := make(map[string]int)
	counts["apple"] = 3
	counts["banana"] = 5
	counts["orange"] = 2
	return counts
}

func main() {
	fmt.Println(createMap())
}
