ရပါတယ်ခင်ဗျာ။ ဒီမှာ `src` (ပုံ) ဒါမှမဟုတ် `initials` (အတိုကောက်) ကိုပြသပေးနိုင်တဲ့ Avatar component တစ်ခုပါ။

```tsx
import React from 'react';

type AvatarProps = {
  src?: string;
  alt?: string;
  initials?: string;
  size?: number; // e.g., 40
};

export function Avatar({ src, alt = 'user avatar', initials, size = 40 }: AvatarProps) {
  const styles: React.CSSProperties = {
    width: size,
    height: size,
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#ccc',
    color: 'white',
