Chắc chắn rồi! Đây là component `Modal` đơn giản mà bạn có thể dùng:

```tsx
import React, { ReactNode, useEffect } from 'react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  children: ReactNode;
  title?: string;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, children, title }) => {
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div style={{ 
      position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, 
      backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', 
      alignItems: 'center', justifyContent: 'center', zIndex: 1000 
    }} onClick={onClose}>
      <div style={{
        backgroundColor: 'white', padding: '20px', borderRadius: '8px', 
        maxWidth: '500px', width: '90%', boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
      }} onClick={e => e.stopPropagation()}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
          {title && <h2 style={{ margin: 0 }}>{title}</h2>}
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '1.5em', cursor: 'pointer' }}>&times;</button>
        </div>
        <div>{children}</div>
      </div>
    </div>
  );
};
```
Bạn có thể điều khiển nó bằng prop `isOpen` và `onClose`. Bạn có cần thêm tính năng nhấn Esc để đóng không?

