```tsx
import React, { ReactNode, useState } from 'react';

interface TabProps {
  label: string;
  children: ReactNode;
}

export const Tab: React.FC<TabProps> = ({ children }) => <>{children}</>;

interface TabsProps {
  children: React.ReactElement<TabProps>[];
  defaultActiveTab?: string;
}

export const Tabs: React.FC<TabsProps> = ({ children, defaultActiveTab }) => {
  const [activeTab, setActiveTab] = useState(
    defaultActiveTab || children[0]?.props.label
  );

  return (
    <div>
      <div style={{ display: 'flex', borderBottom: '1px solid #ccc', marginBottom: '16px' }}>
        {children.map(child => (
          <button
            key={child.props.label}
            onClick={() => setActiveTab(child.props.label)}
            style={{
              padding: '10px 15px', border: 'none', background: 'none', cursor: 'pointer',
              fontWeight: activeTab === child.props.label ? 'bold' : 'normal',
              borderBottom: activeTab === child.props.label ? '2px solid blue' : 'none',
              color: activeTab === child.props.label ? 'blue' : '#555',
              marginRight: '8px'
            }}
          >
            {child.props.label}
          </button>
        ))}
      </div>
      <div style={{ padding: '10px 0' }}>
        {children.find(child => child.props.label === activeTab)}
      </div>
    </div>
  );
};
```
