```csharp
using System;
using System.Text.RegularExpressions;

public class PhoneNumberFormatter
{
    public static string FormatPhoneNumber(string phoneNumber)
    {
        // Hapus semua karakter non-digit
        string digitsOnly = Regex.Replace(phoneNumber, "[^\d]", "");

        // Asumsi nomor telepon 10 digit
        if (digitsOnly.Length == 10)
        {
            return string.Format("({0}) {1}-{2}", 
                                 digitsOnly.Substring(0, 3),
                                 digitsOnly.Substring(3, 3),
                                 digitsOnly.Substring(6, 4));
        }
        return phoneNumber; // Kembalikan asli jika tidak sesuai format 10 digit
    }

    public static void Main(string[] args)
    {
        Console.WriteLine(FormatPhoneNumber("123-456-7890"));   // Output: (123) 456-7890
        Console.WriteLine(FormatPhoneNumber("123.456.7890"));   // Output: (123) 456-7890
        Console.WriteLine(FormatPhoneNumber("invalid"));      // Output: invalid
    }
}
```
Fungsi ini membersihkan digit terlebih dahulu. Apakah Anda membutuhkan format lain atau penanganan negara berbeda?

បាន! បញ្ហាគឺអ្នកមិនបាន `await` ការហៅ `fetch` របស់អ្នកទេ។ នេះជាវិធីកែតម្រូវ:

```javascript
async function fetchData(url) {
  try {
    const response = await fetch(url); // ត្រូវតែ await នៅទីនេះ
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    const data = await response.json(); // ហើយ await នៅទីនេះដែរ
    return data;
  } catch (error) {
    console.error("There was an error fetching the data:", error);
    return null;
  }
}

// ឧទាហរណ៍នៃការប្រើប្រាស់:
// fetchData('https://api.example.com/data').then(data => console.log(data));
```
ការប្រើ `await` នឹងរង់ចាំការបដិសេធ (promise) បញ្ចប់មុននឹងបន្ត។ សង្ឃឹមថាវាជួយបាន!

សួស្ដី! បញ្ហាគឺ `margin: auto` ដំណើរការសម្រាប់ block-level elements ដែលមាន width កំណត់។ រូបភាពគឺជា inline-block តាមលំនាំដើម។ នេះជាវិធីកែតម្រូវ:

```html
<div class="image-container">
  <img src="your-image.jpg" alt="A beautiful landscape">
</div>
```
```css
.image-container {
  text-align: center; /* ដាក់ inline/inline-block elements នៅកណ្តាល */
}

.image-container img {
  display: block; /* ធ្វើឲ្យរូបភាពជា block element */
  margin: 0 auto;  /* ឥឡូវ margin: auto នឹងដំណើរការ */
  max-width: 100%;
  height: auto;
}
```
ឬអ្នកអាចប្រើ Flexbox នៅលើ parent container សម្រាប់ភាពងាយស្រួលជាង! មានសំណួរផ្សេងទេ?

ជំរាបសួរ! បញ្ហាគឺអ្នកកំពុងព្យាយាម update state នៅក្នុង render phase ដែលនឹងមិនដំណើរការ។ `useEffect` គឺជាកន្លែងត្រឹមត្រូវដើម្បីប្រតិកម្មទៅនឹងការផ្លាស់ប្តូរ prop ។ នេះជាវិធីកែតម្រូវ:

```jsx
import React, { useState, useEffect } from 'react';

function AmountDisplay({ initialAmount }) {
  const [amount, setAmount] = useState(initialAmount);

  useEffect(() => {
    setAmount(initialAmount); // Update state នៅពេល initialAmount ផ្លាស់ប្តូរ
  }, [initialAmount]); // Dependency array ដើម្បី trigger effect ពេល prop ផ្លាស់ប្តូរ

  return (
    <div>
      <p>Current Amount: ${amount.toFixed(2)}</p>
      <button onClick={() => setAmount(prev => prev + 10)}>Add $10</button>
    </div>
  );
}

export default AmountDisplay;
```
ឥឡូវនេះ `amount` នឹង update ដោយស្វ័យប្រវត្តិនៅពេល `initialAmount` prop ផ្លាស់ប្តូរពី parent component ។

