```python
import csv

def calculate_total_sales(file_path: str, column_name: str = "Amount") -> float:
    total_sales = 0.0
    try:
        with open(file_path, 'r', newline='', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            for row in reader:
                try:
                    total_sales += float(row[column_name])
                except (KeyError, ValueError):
                    # Skip rows where the column is missing or not a valid number
                    continue
    except FileNotFoundError:
        print(f"Error: The file '{file_path}' was not found.")
        return 0.0
    except Exception as e:
        print(f"An error occurred: {e}")
        return 0.0
    return round(total_sales, 2)

if __name__ == "__main__":
    total = calculate_total_sales('sales.csv')
    print(f"Total sales amount: ${total:.2f}")
```
