Absolutely! Here's a Python script designed to scan your log files for "ERROR" or "FAILURE" lines and print them out:

```python
def find_log_errors(log_file_path: str, keywords: list[str] = None):
    if keywords is None:
        keywords = ["ERROR", "FAILURE"]

    found_errors = []
    try:
        with open(log_file_path, 'r', encoding='utf-8', errors='ignore') as f:
            for line_num, line in enumerate(f, 1):
                for keyword in keywords:
                    if keyword.upper() in line.upper():
                        found_errors.append(f"Line {line_num}: {line.strip()}")
                        break # Stop checking other keywords for this line
    except FileNotFoundError:
        print(f"Error: Log file '{log_file_path}' not found.")
        return
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return

    if found_errors:
        print(f"Found {len(found_errors)} lines containing '{', '.join(keywords)}':\n")
        for error_line in found_errors:
            print(error_line)
    else:
        print(f"No lines found containing '{', '.join(keywords)}' in '{log_file_path}'.")

if __name__ == "__main__":
    find_log_errors('server.log') # Replace 'server.log' with your actual log file name
```
This script is robust and handles common encoding issues. It will print the line number along with the matching line. Would you like to save these error lines to a separate file instead of printing them?

