```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json());

let articles = [
  { id: 1, title: 'ข่าวที่ 1', content: 'เนื้อหาข่าว 1' },
  { id: 2, title: 'ข่าวที่ 2', content: 'เนื้อหาข่าว 2' }
];

app.put('/articles/:id', (req, res) => {
  const articleId = parseInt(req.params.id);
  const { title, content } = req.body;

  const articleIndex = articles.findIndex(a => a.id === articleId);

  if (articleIndex > -1) {
    articles[articleIndex] = { ...articles[articleIndex], title, content };
    res.send(articles[articleIndex]);
  } else {
    res.status(404).send({ message: 'ไม่พบบทความ' });
  }
});

app.listen(port, () => {
  console.log(`เซิร์ฟเวอร์ทำงานที่ http://localhost:${port}`);
});
```
ลองส่ง PUT request ไปที่ `/articles/1` พร้อม JSON `{ "title": "ข่าวใหม่", "content": "เนื้อหาใหม่" }` ดูนะครับ อยากให้มีการตรวจสอบข้อมูลเพิ่มเติมไหมครับ?

