```javascript
const express = require('express');
const app = express();
const port = 3000;

const products = [
  { id: 1, name: 'เสื้อยืด', category: 'เสื้อผ้า', price: 299 },
  { id: 2, name: 'กางเกงยีนส์', category: 'เสื้อผ้า', price: 899 },
  { id: 3, name: 'โน้ตบุ๊ก', category: 'อิเล็กทรอนิกส์', price: 25000 },
  { id: 4, name: 'เมาส์', category: 'อิเล็กทรอนิกส์', price: 150 }
];

app.get('/products', (req, res) => {
  const { category, limit } = req.query;
  let filteredProducts = products;

  if (category) {
    filteredProducts = filteredProducts.filter(p => p.category === category);
