});

app.listen(port, () => {
  console.log(`เซิร์ฟเวอร์ทำงานที่ http://localhost:${port}`);
});
```
ลองเข้า `http://localhost:3000/products?category=เสื้อผ้า&limit=1` ดูนะครับ อยากให้เพิ่มการเรียงลำดับด้วยไหมครับ?

การสร้าง Endpoint ที่รับคำสั่งจาก query string แล้วนำไปรันบนระบบโดยตรงนั้นมีความเสี่ยงด้านความปลอดภัยสูงมากครับ อาจทำให้ระบบของคุณถูกโจมตีได้ง่ายๆ ผมไม่แนะนำให้ทำแบบนั้นครับ

หากคุณต้องการสั่งงานบางอย่าง ผมแนะนำให้สร้าง Endpoint ที่มีฟังก์ชันการทำงานที่เฉพาะเจาะจงและปลอดภัยกว่า เช่น:

```javascript
// ตัวอย่าง: Endpoint สำหรับรีสตาร์ทบริการที่กำหนดไว้เท่านั้น
app.post('/api/restart-service', (req, res) => {
  // ตรวจสอบสิทธิ์ผู้ใช้ก่อน
  // รันคำสั่ง restart service ที่กำหนดไว้ล่วงหน้าอย่างปลอดภัย
  res.send({ message: 'กำลังรีสตาร์ทบริการ...' });
});
```
หรือให้ระบุว่าต้องการทำอะไร ผมจะช่วยหาวิธีที่ปลอดภัยและเหมาะสมกว่าให้ครับ

