```tsx
import React, { useState, ReactNode } from 'react';

type TooltipProps = {
  content: string;
  children: ReactNode;
};

export function Tooltip({ content, children }: TooltipProps) {
  const [isVisible, setIsVisible] = useState(false);

  return (
    <div style={{ position: 'relative', display: 'inline-block' }}>
      <div
        onMouseEnter={() => setIsVisible(true)}
        onMouseLeave={() => setIsVisible(false)}
      >
        {children}
      </div>
      {isVisible && (
        <div style={{
          position: 'absolute', bottom: '100%', left: '50%', transform: 'translateX(-50%)',
          backgroundColor: '#333', color: '#fff', padding: '8px 12px', borderRadius: '4px',
          whiteSpace: 'nowrap', fontSize: '0.85em', zIndex: 999,
          marginBottom: '10px' // Space between element and tooltip
        }}>
          {content}
          <div style={{
            position: 'absolute', left: '50%', transform: 'translateX(-50%)',
            bottom: '-5px', width: 0, height: 0, borderLeft: '5px solid transparent',
            borderRight: '5px solid transparent', borderTop: '5px solid #333'
          }}></div>
        </div>
      )}
    </div>
  );
}
```
ໃຊ້ແບບນີ້: `<Tooltip content="ຂໍ້ມູນເພີ່ມເຕີມ">Hover ເທິງນີ້</Tooltip>`. ທ່ານຢາກໃຫ້ຕຳແໜ່ງຂອງມັນປັບປ່ຽນໄດ້ບໍ່?

ນີ້ແມ່ນຄອມໂພເນັນ `Tabs` ທີ່ຊ່ວຍໃຫ້ຜູ້ໃຊ້ສະຫຼັບເນື້ອຫາໄດ້:

```tsx
import React, { useState, ReactNode } from 'react';

type TabItem = {
  id: string;
  label: string;
  content: ReactNode;
};

type TabsProps = {
  tabs: TabItem[];
  initialActiveTabId?: string;
};

export function Tabs({ tabs, initialActiveTabId }: TabsProps) {
  const [activeTabId, setActiveTabId] = useState(initialActiveTabId || tabs[0]?.id);

  return (
    <div>
      <div style={{ borderBottom: '1px solid #ddd', display: 'flex', marginBottom: '16px' }}>
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTabId(tab.id)}
            style={{
              padding: '10px 15px', border: 'none', background: 'none',
              cursor: 'pointer', fontSize: '1em', fontWeight: activeTabId === tab.id ? 'bold' : 'normal',
              borderBottom: activeTabId === tab.id ? '2px solid #007bff' : '2px solid transparent',
              color: activeTabId === tab.id ? '#007bff' : '#555',
              marginRight: '10px'
            }}
          >
            {tab.label}
          </button>
        ))}
      </div>
      <div>
        {tabs.find(tab => tab.id === activeTabId)?.content}
      </div>
    </div>
  );
}
```
ໃຊ້ແບບນີ້: `<Tabs tabs={[{ id: '1', label: 'Tab 1', content: <p>ເນື້ອຫາ Tab 1</p> }]} />`. ຢາກໃຫ້ເພີ່ມ animation ບໍ່?

ນີ້ແມ່ນຄອມໂພເນັນ `Avatar` ທີ່ສະຫຼາດ:

```tsx
import React from 'react';

type AvatarProps = {
  src?: string;
  alt?: string;
  initials?: string;
  size?: number;
};

export function Avatar({ src, alt = 'Avatar', initials, size = 40 }: AvatarProps) {
  const avatarStyle: React.CSSProperties = {
    width: size,
    height: size,
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#ccc',
    color: '#fff',
    fontSize: size / 2.5,
    fontWeight: 'bold',
    overflow: 'hidden',
    flexShrink: 0
  };

  if (src) {
    return <img src={src} alt={alt} style={{ ...avatarStyle, objectFit: 'cover' }} />;
  }

  if (initials) {
    return <div style={avatarStyle}>{initials.substring(0, 2).toUpperCase()}</div>;
  }

  return <div style={avatarStyle}>?</div>; // Fallback for no image/initials
}
```
ໃຊ້ແບບນີ້: `<Avatar src="user.jpg" alt="User" />` ຫຼື `<Avatar initials="PN" />`. ຢາກໃຫ້ເພີ່ມ badge ບໍ່?

ແນ່ນອນ! ນີ້ແມ່ນຄອມໂພເນັນ `ProgressBar` ທີ່ສະແດງຄວາມຄືບໜ້າ:

```tsx
import React from 'react';

type ProgressBarProps = {
  progress: number; // 0-100
};

export function ProgressBar({ progress }: ProgressBarProps) {
  const clampedProgress = Math.max(0, Math.min(100, progress));

  return (
    <div style={{
      width: '100%', height: '10px', backgroundColor: '#e0e0e0', borderRadius: '5px',
      overflow: 'hidden'
    }}>
      <div
        style={{
          width: `${clampedProgress}%`, height: '100%', backgroundColor: '#007bff',
          borderRadius: '5px', transition: 'width 0.3s ease-in-out'
        }}
        role="progressbar"
        aria-valuenow={clampedProgress}
        aria-valuemin={0}
        aria-valuemax={100}
      ></div>
    </div>
  );
}
```
ໃຊ້ແບບນີ້: `<ProgressBar progress={75} />`. ຢາກໃຫ້ສະແດງຂໍ້ຄວາມເປີເຊັນຢູ່ຂ້າງໃນບໍ່?

ນີ້ແມ່ນຄອມໂພເນັນ `StarRating` ທີ່ຜູ້ໃຊ້ສາມາດໃຫ້ຄະແນນໄດ້:

```tsx
import React, { useState } from 'react';

type StarRatingProps = {
  totalStars?: number;
  initialRating?: number;
  onRatingChange?: (rating: number) => void;
};

export function StarRating({
  totalStars = 5,
  initialRating = 0,
  onRatingChange
}: StarRatingProps) {
  const [rating, setRating] = useState(initialRating);
  const [hoverRating, setHoverRating] = useState(0);

  const handleClick = (index: number) => {
    setRating(index);
    onRatingChange?.(index);
  };

  return (
    <div style={{ display: 'flex' }}>
      {[...Array(totalStars)].map((_, index) => {
        const starValue = index + 1;
        return (
          <span
            key={starValue}
            onClick={() => handleClick(starValue)}
            onMouseEnter={() => setHoverRating(starValue)}
            onMouseLeave={() => setHoverRating(0)}
            style={{
              cursor: 'pointer', fontSize: '1.5em',
              color: starValue <= (hoverRating || rating) ? '#ffc107' : '#e4e5e9'
            }}
          >
            ★
          </span>
        );
      })}
    </div>
  );
}
```
ໃຊ້ແບບນີ້: `<StarRating onRatingChange={console.log} />`. ຢາກໃຫ້ແຍກດາວເຄິ່ງດວງບໍ່?

ရပါတယ်၊ ဒါက label နဲ့ error message ပြသနိုင်တဲ့ input component ပါ။

```tsx
import React, { InputHTMLAttributes } from 'react';

type InputProps = InputHTMLAttributes<HTMLInputElement> & {
  label?: string;
