ဒီမှာ အသုံးပြုသူကို အချက်အလက်တွေ ခဏတာပြသဖို့ သုံးနိုင်တဲ့ toast component ပါ။

```tsx
import React, { ReactNode, useEffect, useState } from 'react';

type ToastProps = {
  message: string | ReactNode;
  duration?: number; // milliseconds
  onClose?: () => void;
};

export function Toast({ message, duration = 3000, onClose }: ToastProps) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (duration > 0) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onClose?.();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [duration, onClose]);

  if (!isVisible) return null;

  return (
    <div style={{
      position: 'fixed', top: '20px', right: '20px', zIndex: 9999,
      backgroundColor: '#333', color: 'white', padding: '10px 15px',
      borderRadius: '5px', boxShadow: '0 2px 10px rgba(0,0,0,0.2)',
      opacity: isVisible ? 1 : 0, transition: 'opacity 0.3s ease-in-out'
    }}>
      {message}
    </div>
  );
}
```
အသုံးပြုပုံ- `<Toast message='အောင်မြင်စွာ သိမ်းဆည်းပြီးပါပြီ!' />`။ တစ်ကြိမ်တည်း toast အများကြီး ပြသဖို့ စီမံခန့်ခွဲတဲ့ context ဘယ်လိုဖန်တီးရမလဲ သိချင်ပါသလား။

ရပါတယ်၊ ဒါက label နဲ့ controlled checked state ပါဝင်တဲ့ custom checkbox component ပါ။

