Chắc chắn rồi! Đây là một ví dụ về endpoint PUT trong Express để cập nhật một đối tượng theo ID. Chúng ta sẽ giả định có một mảng các đối tượng:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json());

let items = [
  { id: 1, name: 'Bút', price: 10 },
  { id: 2, name: 'Sách', price: 50 }
];

app.put('/items/:id', (req, res) => {
  const itemId = parseInt(req.params.id);
  const updatedItem = req.body;
  const index = items.findIndex(item => item.id === itemId);

  if (index !== -1) {
    items[index] = { ...items[index], ...updatedItem }; // Cập nhật
    res.json({ message: 'Item đã cập nhật thành công', data: items[index] });
  } else {
    res.status(404).json({ message: 'Không tìm thấy Item' });
  }
});

app.listen(port, () => {
  console.log(`Server chạy tại http://localhost:${port}`);
});
```
Bạn có thể gửi yêu cầu PUT đến `/items/1` với dữ liệu mới. Bạn muốn xử lý PATCH (cập nhật một phần) không?

