```python
from fastapi import FastAPI, HTTPException

app = FastAPI()

# Dữ liệu giả định
items_db = {
    1: {"name": "Áo sơ mi"},
    2: {"name": "Quần jean"},
    3: {"name": "Giày thể thao"}
