Được chứ! Bạn có thể sử dụng middleware trong Express để kiểm tra token đơn giản. Đây là một ví dụ:

```javascript
const express = require('express');
const app = express();
const port = 3000;

const MY_SECRET_TOKEN = 'supersecrettoken123'; // Thay bằng token thật của bạn

// Middleware kiểm tra token
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Lấy token từ 'Bearer TOKEN'

  if (token === MY_SECRET_TOKEN) {
    next(); // Cho phép yêu cầu tiếp tục nếu token khớp
  } else {
    res.status(403).json({ message: 'Truy cập bị từ chối: Token không hợp lệ' });
  }
};

// Áp dụng middleware cho một route cụ thể
app.get('/protected-data', authenticateToken, (req, res) => {
  res.json({ message: 'Đây là dữ liệu được bảo vệ!' });
});

// Một route không cần bảo vệ
app.get('/public-data', (req, res) => {
  res.json({ message: 'Đây là dữ liệu công khai.' });
});

app.listen(port, () => {
  console.log(`Server chạy tại http://localhost:${port}`);
});
```
Để truy cập `/protected-data`, bạn cần gửi header `Authorization: Bearer supersecrettoken123`. Bạn có muốn tích hợp với JWT không?

