นี่คือ `ToggleSwitch` component ที่สามารถสลับสถานะได้ครับ:

```tsx
import React, { InputHTMLAttributes } from 'react';

type ToggleSwitchProps = Omit<InputHTMLAttributes<HTMLInputElement>, 'type'> & {
  checked: boolean;
  onChange: (checked: boolean) => void;
};

export const ToggleSwitch: React.FC<ToggleSwitchProps> = ({ checked, onChange, id, ...rest }) => {
  const switchId = id || 'toggle-switch';
  return (
    <label
      htmlFor={switchId}
      style={{
        position: 'relative',
        display: 'inline-block',
        width: '44px',
        height: '24px',
        cursor: 'pointer',
      }}
    >
      <input
        type="checkbox"
        id={switchId}
        checked={checked}
        onChange={(e) => onChange(e.target.checked)}
        style={{ opacity: 0, width: 0, height: 0 }}
        {...rest}
      />
      <span
        style={{
          position: 'absolute',
          cursor: 'pointer',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: checked ? '#007bff' : '#ccc',
          borderRadius: '24px',
          transition: 'background-color 0.2s',
        }}
      >
        <span
          style={{
            position: 'absolute',
            content: '""',
            height: '16px',
            width: '16px',
            left: '4px',
            bottom: '4px',
            backgroundColor: 'white',
            borderRadius: '50%',
            transition: 'transform 0.2s',
            transform: checked ? 'translateX(20px)' : 'translateX(0)',
          }}
        />
      </span>
    </label>
  );
};
```
วิธีใช้งาน: `<ToggleSwitch checked={isDarkMode} onChange={setIsDarkMode} />` ครับ

แน่นอนครับ นี่คือ `Alert` component ที่มีประเภทและปุ่มปิด:

```tsx
import React, { ReactNode, useState } from 'react';

type AlertType = 'success' | 'error' | 'info' | 'warning';

type AlertProps = {
  type: AlertType;
  message: ReactNode;
  onClose?: () => void;
};

const typeColors: Record<AlertType, string> = {
  success: '#d4edda',
  error: '#f8d7da',
  info: '#d1ecf1',
  warning: '#fff3cd',
};

const typeTextColors: Record<AlertType, string> = {
  success: '#155724',
  error: '#721c24',
  info: '#0c5460',
  warning: '#856404',
};

export const Alert: React.FC<AlertProps> = ({ type, message, onClose }) => {
  const [isVisible, setIsVisible] = useState(true);

  const handleClose = () => {
    setIsVisible(false);
    onClose?.();
  };

  if (!isVisible) return null;

  return (
    <div
      style={{
        padding: '12px 20px',
        marginBottom: '16px',
        border: `1px solid ${typeColors[type].replace('d', 'b').replace('f', 'e')}`,
        borderRadius: '4px',
        backgroundColor: typeColors[type],
        color: typeTextColors[type],
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
      }}
      role="alert"
    >
      <span>{message}</span>
      {onClose && (
        <button
          onClick={handleClose}
          style={{
            background: 'none',
            border: 'none',
            fontSize: '18px',
            cursor: 'pointer',
            color: typeTextColors[type],
            marginLeft: '16px',
          }}
        >
          &times;
        </button>
      )}
    </div>
  );
};
```
คุณสามารถใช้งานได้ เช่น `<Alert type="success" message="บันทึกข้อมูลสำเร็จ!" onClose={() => console.log('ปิด Alert')} />` ครับ

ได้เลยครับ นี่คือ `Card` component ที่มีส่วนประกอบต่างๆ:

