ลองใช้แบบนี้ดูนะครับ: `<Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="ข้อมูลเพิ่มเติม">สวัสดี</Modal>`

ແນ່ນອນ! ນີ້ແມ່ນຟັງຊັນ JavaScript ທີ່ໃຊ້ `Intl.NumberFormat` ເພື່ອຈັດຮູບແບບຕົວເລກເປັນເງິນກີບລາວ:

```javascript
function formatLaoKip(amount) {
  return new Intl.NumberFormat('lo-LA', {
    style: 'currency',
    currency: 'LAK',
    minimumFractionDigits: 0, // ປົກກະຕິແລ້ວບໍ່ມີທົດສະນິຍົມສໍາລັບ LAK
    maximumFractionDigits: 0
  }).format(amount);
}

// ຕົວຢ່າງການນໍາໃຊ້
console.log(formatLaoKip(1234567)); // ຈະສະແດງ "1,234,567 LAK"
console.log(formatLaoKip(50000));   // ຈະສະແດງ "50,000 LAK"
```
