```tsx
import React, { useState, ReactNode } from 'react';

type TabProps = {
  label: string;
  children: ReactNode;
};

export const TabPanel: React.FC<TabProps> = ({ children }) => (
  <div style={{ padding: '16px', border: '1px solid #eee', borderTop: 'none', borderRadius: '0 0 8px 8px' }}>
    {children}
  </div>
);

type TabsProps = {
  children: React.ReactElement<TabProps>[];
};

export const Tabs: React.FC<TabsProps> = ({ children }) => {
  const [activeTab, setActiveTab] = useState(children[0]?.props.label || '');

  return (
    <div>
      <div style={{ display: 'flex', borderBottom: '1px solid #eee' }}>
        {children.map(child => {
          const label = child.props.label;
          return (
            <button
              key={label}
              onClick={() => setActiveTab(label)}
              style={{
                padding: '10px 15px', border: 'none', background: 'none', cursor: 'pointer',
                borderBottom: activeTab === label ? '2px solid #007bff' : '2px solid transparent',
                color: activeTab === label ? '#007bff' : '#333',
                fontWeight: activeTab === label ? 'bold' : 'normal',
                transition: 'all 0.3s ease'
              }}
            >
              {label}
            </button>
          );
        })}
      </div>
      {children.map(child => {
        if (child.props.label === activeTab) {
          return <div key={child.props.label}>{child.props.children}</div>;
        }
        return null;
      })}
    </div>
  );
};
```
