Tentu, ini skrip Python untuk mengekstrak nama pengguna dari file JSON Anda:

```python
import json

def get_usernames(json_file_path: str) -> list[str]:
    usernames = []
    with open(json_file_path, 'r', encoding='utf-8') as f:
        data = json.load(f)
        if isinstance(data, list):
            for item in data:
                if 'username' in item:
                    usernames.append(item['username'])
        elif isinstance(data, dict) and 'username' in data:
            usernames.append(data['username'])
    return usernames

if __name__ == "__main__":
    # Contoh penggunaan dengan file bernama 'users.json'
    # Isi users.json bisa berupa [{"username": "alice"}, {"username": "bob"}] atau {"username": "charlie"}
    print(get_usernames("users.json"))
```
