```php
<?php

function isPrime(int $num): bool
{
    if ($num <= 1) return false;
    if ($num <= 3) return true;
    if ($num % 2 === 0 || $num % 3 === 0) return false;

    for ($i = 5; $i * $i <= $num; $i += 6) {
        if ($num % $i === 0 || $num % ($i + 2) === 0) {
            return false;
        }
    }
    return true;
}

// Ví dụ sử dụng:
echo isPrime(11) ? "11 là số nguyên tố\n" : "11 không là số nguyên tố\n"; // true
echo isPrime(15) ? "15 là số nguyên tố\n" : "15 không là số nguyên tố\n"; // false

?>
```
