```go
package main

import (
	"fmt"
	"strings"
)

func ReverseString(s string) string {
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	return string(runes)
}

func main() {
	fmt.Println(ReverseString("hello"))         // olleh
	fmt.Println(ReverseString("Rnai.io"))       // oi.ianR
	fmt.Println(ReverseString("Xin chào Rnai")) // ianR oàhc niX
}
```
