console.log(messageClean); // Output: Your account is active.
```

ဒီပုံစံက ကုတ်လိုင်းကို တိုစေပြီး condition တစ်ခုတည်းအတွက်ဆို ပိုအဆင်ပြေပါတယ်။ တခြား condition တွေကိုလည်း ပြန်လည်ပြင်ဆင်ဖို့ စိတ်ဝင်စားပါသလား?

မင်္ဂလာပါခင်ဗျာ! Java မှာ string တွေ အများကြီးဆက်တဲ့အခါ `+` operator ကိုသုံးရင် performance အနည်းငယ်ကျနိုင်ပါတယ်။ String က immutable ဖြစ်တဲ့အတွက် `+` တိုင်းမှာ object အသစ်တစ်ခုဖန်တီးနေရလို့ပါ။ ဒါကို `StringBuilder` (သို့မဟုတ် `StringBuffer`) ကိုသုံးပြီး ပိုပြီး effective ဖြစ်အောင် ရေးလို့ရပါတယ်ခင်ဗျာ။

```java
// လက်ရှိပုံစံ (ဥပမာ)
String result = "";
for (int i = 0; i < 5; i++) {
    result += i + " ";
}
System.out.println(result.trim()); // Output: 0 1 2 3 4

// ပိုမိုသန့်ရှင်းသောပုံစံ (StringBuilder)
StringBuilder sb = new StringBuilder();
for (int i = 0; i < 5; i++) {
    sb.append(i).append(" ");
}
String resultClean = sb.toString().trim();
System.out.println(resultClean); // Output: 0 1 2 3 4
```

`StringBuilder` က string တွေကို ပိုမိုထိရောက်စွာ စုစည်းပေးနိုင်တဲ့အတွက် performance ပိုကောင်းစေပါတယ်။

ဟုတ်ကဲ့၊ PHP မှာ array ထဲက item တွေကို condition တစ်ခုနဲ့ ဖယ်ထုတ်ချင်ရင် `array_filter()` function ကို သုံးတာက ပိုပြီး သန့်ရှင်းပြီး ထိရောက်ပါတယ်ခင်ဗျာ။ Loop ပတ်ပြီး ကိုယ်တိုင်စီစစ်နေစရာ မလိုတော့ပါဘူး။

```php
// လက်ရှိပုံစံ (ဥပမာ) - ကိန်းဂဏန်းစုံတွေကိုသာထားပြီး ကိန်းဂဏန်းမတွေကို ဖယ်ထုတ်
$numbers = [1, 2, 3, 4, 5, 6];
$evenNumbers = [];
foreach ($numbers as $num) {
    if ($num % 2 === 0) {
        $evenNumbers[] = $num;
    }
}
print_r($evenNumbers); // Output: Array ( [0] => 2 [1] => 4 [2] => 6 )

// ပိုမိုသန့်ရှင်းသောပုံစံ (array_filter)
$numbersClean = [1, 2, 3, 4, 5, 6];
$evenNumbersClean = array_filter($numbersClean, function($num) {
    return $num % 2 === 0;
});
print_r($evenNumbersClean); // Output: Array ( [1] => 2 [3] => 4 [5] => 6 )
```

`array_filter()` က callback function နဲ့အတူ သုံးတဲ့အခါ ကုတ်ကို ပိုပြီး ဖတ်ရလွယ်စေပါတယ်။

မင်္ဂလာပါ! CSS မှာ color, padding စတဲ့ value တွေကို ခဏခဏ ပြန်သုံးရတဲ့အခါ CSS custom properties (သို့မဟုတ် variables) ကို သုံးပြီး ပိုပြီး ထိန်းချုပ်ရလွယ်အောင် ရေးလို့ရပါတယ်ခင်ဗျာ။ ဒါမှ တစ်နေရာတည်းကနေ ပြောင်းလဲလိုက်တာနဲ့ တစ်လျှောက်လုံး ပြောင်းလဲသွားမှာပါ။

```css
/* လက်ရှိပုံစံ (ဥပမာ) */
