Merging CSVs by a common ID is a perfect task for `pandas`! It's very efficient. Here's how you can do it:

```python
import pandas as pd

def merge_csv_by_id(users_path: str, orders_path: str, output_path: str, common_id_column: str = "user_id"):
    try:
        users_df = pd.read_csv(users_path)
        orders_df = pd.read_csv(orders_path)

        merged_df = pd.merge(users_df, orders_df, on=common_id_column, how='inner')
        merged_df.to_csv(output_path, index=False)
        print(f"Files merged successfully to {output_path}!")

    except FileNotFoundError as e:
        print(f"Error: One of the input files was not found: {e}")
    except KeyError:
        print(f"Error: The column '{common_id_column}' was not found in one of the CSVs.")
    except Exception as e:
        print(f"An error occurred during merging: {e}")

if __name__ == "__main__":
    # Create dummy CSVs for testing
    users_data = {'user_id': [1, 2, 3], 'name': ['Alice', 'Bob', 'Charlie']}
    orders_data = {'user_id': [1, 2, 4], 'order_id': ['A001', 'B002', 'D004'], 'amount': [100, 150, 200]}

    pd.DataFrame(users_data).to_csv("users.csv", index=False)
    pd.DataFrame(orders_data).to_csv("orders.csv", index=False)

    merge_csv_by_id("users.csv", "orders.csv", "merged_data.csv", "user_id")
```
