```python
import csv

def filter_csv_by_status(input_path: str, output_path: str, status_column: str = 'status', target_status: str = 'aktif'):
    try:
        with open(input_path, 'r', newline='', encoding='utf-8') as infile,
             open(output_path, 'w', newline='', encoding='utf-8') as outfile:

            reader = csv.DictReader(infile)
            if not reader.fieldnames:
                print("Ralat: Fail input kosong atau tiada pengepala.")
                return

            writer = csv.DictWriter(outfile, fieldnames=reader.fieldnames)
            writer.writeheader()

            for row in reader:
                if row.get(status_column) == target_status:
                    writer.writerow(row)
        print(f"Fail '{input_path}' telah ditapis dan disimpan ke '{output_path}'.")
    except FileNotFoundError:
        print(f"Ralat: Fail '{input_path}' tidak ditemui.")
    except Exception as e:
        print(f"Berlaku ralat: {e}")

if __name__ == '__main__':
    filter_csv_by_status('data_input.csv', 'data_aktif.csv')
```
