```python
import re
from collections import Counter

def count_word_frequency(filepath: str) -> dict:
    try:
        with open(filepath, 'r', encoding='utf-8') as file:
            text = file.read()
            # Menukar semua teks kepada huruf kecil dan mencari perkataan
            words = re.findall(r'\b\w+\b', text.lower())
            return Counter(words)
    except FileNotFoundError:
        print(f"Ralat: Fail '{filepath}' tidak ditemui.")
        return {}
    except Exception as e:
        print(f"Berlaku ralat: {e}")
        return {}

if __name__ == '__main__':
    # Contoh penggunaan dengan fail 'contoh.txt'
    frequencies = count_word_frequency('contoh.txt')
    for word, count in frequencies.most_common(10): # Papar 10 perkataan paling kerap
        print(f"'{word}': {count}")
```
Skrip ini akan mengabaikan tanda baca dan membezakan antara huruf besar dan kecil. Adakah anda ingin menyimpan hasilnya ke fail?

Tentu, ini skrip Python yang boleh membantu anda menamakan semula fail gambar JPEG anda dengan awalan 'foto_':

```python
import os

def rename_jpg_files(folder_path: str, prefix: str = 'foto_'):
    try:
        files = os.listdir(folder_path)
        renamed_count = 0

        for filename in files:
            if filename.lower().endswith('.jpg'):
                old_filepath = os.path.join(folder_path, filename)
                new_filename = prefix + filename
                new_filepath = os.path.join(folder_path, new_filename)

                # Elak menamakan semula fail yang sudah ada awalan
                if not filename.startswith(prefix):
                    os.rename(old_filepath, new_filepath)
                    print(f"Berjaya menamakan semula '{filename}' kepada '{new_filename}'")
                    renamed_count += 1
                else:
                    print(f"Melangkau '{filename}' (sudah ada awalan '{prefix}').")

        print(f"Selesai. {renamed_count} fail JPG telah dinamakan semula dalam '{folder_path}'.")

    except FileNotFoundError:
        print(f"Ralat: Folder '{folder_path}' tidak ditemui.")
    except Exception as e:
        print(f"Berlaku ralat: {e}")

if __name__ == '__main__':
    # Gantikan 'gambar_saya' dengan laluan folder anda yang sebenar
    rename_jpg_files('gambar_saya')
```
