def find_errors_in_log(log_filepath: str):
    print(f"Mencari 'ERROR' dalam fail log: {log_filepath}...")
    error_found = False
    try:
        with open(log_filepath, 'r', encoding='utf-8', errors='ignore') as file:
            for line_num, line in enumerate(file, 1):
                if 'ERROR' in line:
                    print(f"Baris {line_num}: {line.strip()}")
                    error_found = True

        if not error_found:
            print("Tiada baris yang mengandungi 'ERROR' ditemui.")

    except FileNotFoundError:
        print(f"Ralat: Fail log '{log_filepath}' tidak ditemui.")
    except Exception as e:
        print(f"Berlaku ralat: {e}")

if __name__ == '__main__':
    # Gantikan 'aplikasi.log' dengan nama fail log anda yang sebenar
    find_errors_in_log('aplikasi.log')
```
