Absolutely! Here's a JavaScript function to compute the factorial iteratively:

```javascript
function factorial(n) {
  if (n < 0) {
    throw new Error("Factorial is not defined for negative numbers.");
  }
  if (n === 0) {
    return 1; // Factorial of 0 is 1
  }
  let result = 1;
  for (let i = 1; i <= n; i++) {
    result *= i;
  }
  return result;
}

// Example Usage:
console.log(`Factorial of 5: ${factorial(5)}`);   // 120
console.log(`Factorial of 0: ${factorial(0)}`);   // 1
// console.log(factorial(-3)); // Throws an error
```
This function handles non-negative integers correctly. Let me know if you'd prefer a recursive version!

Certainly! JavaScript's `Intl.NumberFormat` is perfect for this. Here's how to format a number as USD:

```javascript
function formatUSD(amount) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

// Example Usage:
console.log(`1234.56: ${formatUSD(1234.56)}`);     // $1,234.56
console.log(`99.9: ${formatUSD(99.9)}`);           // $99.90
console.log(`1000000: ${formatUSD(1000000)}`);   // $1,000,000.00
