Maaari mo itong gawin gamit ang Python upang mag-filter ng mga linya na naglalaman ng 'error' at i-save ang mga ito sa bagong file:

```python
def filter_log_file(input_file: str, output_file: str, keyword: str = "error"):
    try:
        with open(input_file, 'r', encoding='utf-8') as infile,
             open(output_file, 'w', encoding='utf-8') as outfile:
            for line in infile:
                if keyword.lower() in line.lower():
                    outfile.write(line)
        print(f"Filtered lines with '{keyword}' saved to '{output_file}'.")
    except FileNotFoundError:
        print(f"Error: Input file '{input_file}' not found.")
    except Exception as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
    filter_log_file("app.log", "errors.log", "error")
```
