import React from 'react';

type AlertVariant = 'info' | 'success' | 'error';

type AlertProps = {
  message: string;
  variant?: AlertVariant;
};

const variantStyles: Record<AlertVariant, React.CSSProperties> = {
  info: { backgroundColor: '#e0f7fa', color: '#006064' },
