ได้เลยครับ นี่คือ Express API สำหรับอัปเดตข้อมูลผู้ใช้ด้วยเมธอด PUT/PATCH:

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json()); // สำหรับอ่าน JSON body

let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

app.put('/api/users/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const userIndex = users.findIndex(u => u.id === id);

  if (userIndex !== -1) {
    users[userIndex] = { ...users[userIndex], ...req.body, id };
    res.json({ message: 'User updated successfully', user: users[userIndex] });
  } else {
    res.status(404).send('User not found');
  }
});

app.listen(port, () => {
  console.log(`เซิร์ฟเวอร์ทำงานที่ http://localhost:${port}`);
});
```
คุณสามารถส่ง PUT request ไปที่ `/api/users/1` พร้อม JSON body เช่น `{"name": "Alicia"}` ครับ

