ได้เลยครับ นี่คือ `Table` component แบบง่ายๆ ที่คุณสามารถใช้งานได้:

```tsx
import React from 'react';

type Column<T> = {
  key: keyof T;
  header: string;
  render?: (item: T) => React.ReactNode;
};

type TableProps<T extends object> = {
  data: T[];
  columns: Column<T>[];
};

export const Table = <T extends object>({ data, columns }: TableProps<T>) => {
  return (
    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
      <thead>
        <tr>
          {columns.map((col) => (
            <th key={String(col.key)} style={{ border: '1px solid #ddd', padding: '8px', textAlign: 'left', backgroundColor: '#f2f2f2' }}>
              {col.header}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {data.map((item, rowIndex) => (
          <tr key={rowIndex}>
            {columns.map((col, colIndex) => (
              <td key={String(col.key) + '-' + rowIndex} style={{ border: '1px solid #ddd', padding: '8px' }}>
                {col.render ? col.render(item) : String(item[col.key])}
              </td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
};
```
คุณสามารถใช้งานโดยส่ง `data` และ `columns` เข้าไปได้เลย เช่น `<Table data={myData} columns={myColumns} />` ครับ

