Tuyệt vời, đây là hàm JavaScript để kiểm tra palindrome nhé:

```javascript
function isPalindrome(text) {
  const cleanedText = text.toLowerCase().replace(/[^a-z0-9]/g, '');
  const reversedText = cleanedText.split('').reverse().join('');
  return cleanedText === reversedText;
}

// Ví dụ sử dụng:
console.log(isPalindrome("madam"));         // true
console.log(isPalindrome("A man, a plan, a canal: Panama")); // true
console.log(isPalindrome("hello"));         // false
```
Hàm này sẽ bỏ qua khoảng trắng và dấu câu, đồng thời không phân biệt chữ hoa, chữ thường. Bạn có thích thế không?

Chắc chắn rồi, đây là hàm JavaScript dùng regex để kiểm tra định dạng số điện thoại di động Việt Nam:

```javascript
function isValidVietnamesePhoneNumber(phoneNumber) {
  // Loại bỏ khoảng trắng và dấu gạch ngang
  const cleanedNumber = phoneNumber.replace(/[-\s]/g, '');

  // Regex cho các đầu số phổ biến của Việt Nam (03, 05, 07, 08, 09) và 10 số
  const phoneRegex = /^(0|\+84)(3|5|7|8|9)[0-9]{8}$/;

  return phoneRegex.test(cleanedNumber);
}

// Ví dụ sử dụng:
console.log(isValidVietnamesePhoneNumber("0987654321"));   // true
console.log(isValidVietnamesePhoneNumber("+84321234567")); // true
console.log(isValidVietnamesePhoneNumber("0123456789"));   // false (đầu số cũ)
console.log(isValidVietnamesePhoneNumber("098-765-4321")); // true
```
Hàm này chấp nhận cả định dạng bắt đầu bằng `0` và `+84`, đồng thời bỏ qua dấu gạch ngang hoặc khoảng trắng. Có phức tạp quá không?

