Tuy nhiên, nếu bạn muốn trích xuất các chuỗi số chung (không phải thẻ tín dụng) từ một văn bản, tôi có thể giúp bạn làm một hàm JavaScript như thế này:

```javascript
function extractNumbers(text) {
  const numberRegex = /\b\d{4}[-\s]?\d{4}[-\s]?\d{4}[-\s]?\d{4}\b|\b\d{13,16}\b/g;
  return text.match(numberRegex) || [];
}

// Ví dụ sử dụng:
const sampleText = "Mã số đơn hàng là 1234-5678-9012-3456. ID sản phẩm là 9876543210. Ngày 2023.";
console.log(extractNumbers(sampleText)); // ['1234-5678-9012-3456', '9876543210']
```
Hàm này sẽ tìm các chuỗi 13-16 chữ số liền kề hoặc theo nhóm 4 chữ số có dấu gạch ngang/khoảng trắng. Nó không đảm bảo là số thẻ tín dụng, chỉ là các chuỗi số có cấu trúc tương tự. Bạn nghĩ sao?

Chắc chắn rồi! Đây là hàm JavaScript tạo mật khẩu an toàn theo yêu cầu của bạn:

```javascript
function generatePassword(length = 12, includeUppercase = true, includeLowercase = true, includeNumbers = true, includeSpecial = true) {
    const uppercase = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const lowercase = 'abcdefghijklmnopqrstuvwxyz';
    const numbers = '0123456789';
    const special = '!@#$%^&*()_+[]{}|;:,.<>?';

    let characters = '';
    if (includeUppercase) characters += uppercase;
    if (includeLowercase) characters += lowercase;
    if (includeNumbers) characters += numbers;
    if (includeSpecial) characters += special;

    if (characters.length === 0) {
        throw new Error('Vui lòng chọn ít nhất một loại ký tự.');
    }

    let password = '';
    for (let i = 0; i < length; i++) {
        const randomIndex = Math.floor(Math.random() * characters.length);
        password += characters[randomIndex];
    }
    return password;
}

// Ví dụ sử dụng:
console.log(generatePassword(16)); // Mật khẩu 16 ký tự
