<?php

function getWorkingDays(string $startDate, string $endDate): int
{
    $start = new DateTime($startDate);
    $end = new DateTime($endDate);
    $end->modify('+1 day'); // Include the end date itself

    $interval = new DateInterval('P1D');
    $period = new DatePeriod($start, $interval, $end);

    $workingDays = 0;
    foreach ($period as $date) {
        if ($date->format('N') < 6) { // 1 = Monday, 7 = Sunday
            $workingDays++;
        }
    }
    return $workingDays;
}

// Ví dụ sử dụng:
echo "Số ngày làm việc từ 2024-10-01 đến 2024-10-31: " . getWorkingDays('2024-10-01', '2024-10-31') . " ngày.";
// Output: Số ngày làm việc từ 2024-10-01 đến 2024-10-31: 23 ngày.

?>
```
