```javascript
function countWords(sentence) {
  // Tanggalin ang leading/trailing whitespace at hatiin sa bawat space
  const words = sentence.trim().split(/\s+/);
  // I-filter ang mga empty string na maaaring mangyari mula sa multiple spaces
  const filteredWords = words.filter(word => word.length > 0);
  return filteredWords.length;
}

// Example usage:
console.log("Words in 'Hello world':", countWords('Hello world')); // 2
console.log("Words in '   This is a test   ':", countWords('   This is a test   ')); // 4
console.log("Words in '':", countWords('')); // 0
console.log("Words in 'One. Two. Three.':", countWords('One. Two. Three.')); // 3
```
