Medyo kumplikado po ang buong toast/notification *system* sa iisang component lang, dahil kailangan nito ng global state at management. Pero, heto ang isang simpleng React component para *ipakita* ang isang notification message na may timer at dismiss button:

```tsx
import React, { useEffect, useState } from 'react';

type ToastProps = {
  message: string;
  duration?: number; // milliseconds
  onDismiss?: () => void;
};

export function Toast({ message, duration = 3000, onDismiss }: ToastProps) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (duration > 0) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onDismiss?.();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [duration, onDismiss]);

  if (!isVisible) return null;

  return (
    <div style={{
      backgroundColor: '#333', color: 'white', padding: '10px 15px',
      borderRadius: '4px', margin: '10px', display: 'flex',
      alignItems: 'center', justifyContent: 'space-between',
      maxWidth: '300px', boxShadow: '0 2px 5px rgba(0,0,0,0.2)'
    }}>
      <span>{message}</span>
      <button
        onClick={() => { setIsVisible(false); onDismiss?.(); }}
        style={{ background: 'none', border: 'none', color: 'white', fontSize: '1.2em', cursor: 'pointer', marginLeft: '10px' }}
      >
        &times;
      </button>
    </div>
  );
}
```
Kailangan niyo po ng parent component na mag-ma-manage ng listahan ng toasts para maging isang kumpletong notification system. Okay lang po ba ito para sa inyo?

