Tentu, ini contoh endpoint PUT di Express.js untuk memperbarui produk:

```javascript
const express = require('express');
const app = express();
app.use(express.json()); // Untuk parse body JSON

let products = [
  { id: 1, name: 'Laptop', price: 12000000 },
  { id: 2, name: 'Mouse', price: 250000 }
];

app.put('/products/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const productIndex = products.findIndex(p => p.id === id);

  if (productIndex !== -1) {
    products[productIndex] = { ...products[productIndex], ...req.body };
    res.json({ message: 'Produk berhasil diperbarui', product: products[productIndex] });
  } else {
    res.status(404).json({ message: 'Produk tidak ditemukan' });
  }
});

app.listen(3000, () => console.log('Server berjalan di port 3000'));
```
Ini akan memperbarui produk berdasarkan ID. Coba kirim `PUT` ke `/products/1` dengan body `{"price": 12500000}`. Ada kebutuhan untuk validasi input?

Tentu, ini endpoint Express dengan filter query parameter:

```javascript
const express = require('express');
const app = express();

const orders = [
  { id: 1, item: 'Buku', status: 'pending' },
  { id: 2, item: 'Pena', status: 'completed' },
  { id: 3, item: 'Pensil', status: 'pending' }
];

app.get('/orders', (req, res) => {
  const { status } = req.query;
  if (status) {
    const filteredOrders = orders.filter(order => order.status === status);
    res.json(filteredOrders);
  } else {
    res.json(orders);
  }
});

app.listen(3000, () => console.log('Server berjalan di port 3000'));
```
Coba akses `/orders` untuk semua, atau `/orders?status=pending` untuk yang difilter. Ingin filter lebih dari satu kriteria?

Ini contoh middleware sederhana di Express.js untuk otentikasi token:

```javascript
const express = require('express');
const app = express();

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Format: Bearer TOKEN

  if (token === 'mysecrettoken123') { // Ganti dengan logika validasi token asli
    next(); // Lanjutkan ke handler route
  } else {
    res.sendStatus(401); // Unauthorized
  }
};

app.get('/protected-data', authenticateToken, (req, res) => {
  res.json({ message: 'Data rahasia!' });
});

app.get('/public-data', (req, res) => {
  res.json({ message: 'Data publik.' });
});

app.listen(3000, () => console.log('Server berjalan di port 3000'));
```
Tambahkan `authenticateToken` ke route yang ingin dilindungi. Ini adalah dasar, untuk produksi, pertimbangkan JWT atau OAuth. Perlu contoh implementasi token yang lebih kompleks?

