```tsx
import React, { ReactNode } from 'react';

type Props = {
  isOpen: boolean;
  onClose: () => void;
  children: ReactNode;
};

export function Modal({ isOpen, onClose, children }: Props) {
  if (!isOpen) return null;

  return (
    <div style={{
      position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
      backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center'
    }} onClick={onClose}>
      <div style={{
        backgroundColor: 'white', padding: '20px', borderRadius: '8px', maxWidth: '500px',
        width: '90%', boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
      }} onClick={e => e.stopPropagation()}>
        <button onClick={onClose} style={{ float: 'right', border: 'none', background: 'none', fontSize: '1.2em' }}>&times;</button>
        {children}
      </div>
    </div>
  );
}
```
ທ່ານສາມາດຄວບຄຸມການເປີດ-ປິດດ້ວຍ `isOpen` ແລະ `onClose` ໄດ້. ຢາກໃຫ້ເພີ່ມ animation ນຳບໍ່?

