បានការីយ៍! នេះជា component Alert ដែលអាចបាត់ដោយខ្លួនឯង:

```tsx
import React, { useEffect, useState } from 'react';

type AlertType = 'success' | 'error' | 'info';

type Props = {
  message: string;
  type?: AlertType;
  duration?: number; // in milliseconds
  onClose?: () => void;
};

export function Alert({ message, type = 'info', duration = 3000, onClose }: Props) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (duration > 0) {
      const timer = setTimeout(() => {
        setIsVisible(false);
        onClose?.();
      }, duration);
      return () => clearTimeout(timer);
    }
  }, [duration, onClose]);

  if (!isVisible) return null;

  const backgroundColor = {
    success: '#d4edda',
    error: '#f8d7da',
    info: '#d1ecf1',
  }[type];

  const color = {
    success: '#155724',
    error: '#721c24',
    info: '#0c5460',
  }[type];

  return (
    <div
      style={{
        padding: '1rem',
        marginBottom: '1rem',
        borderRadius: '4px',
        backgroundColor,
        color,
        border: `1px solid ${
          {
            success: '#c3e6cb',
            error: '#f5c6cb',
            info: '#bee5eb',
          }[type]
        }`,
      }}
    >
      {message}
    </div>
  );
}
```
អ្នកអាចប្រើវាដូចនេះ: `<Alert message="ទិន្នន័យត្រូវបានរក្សាទុក!" type="success" duration={5000} />`។

ជាការពិត! នេះជា component Pagination សម្រាប់រុករកទំព័រ:

```tsx
import React from 'react';

type Props = {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
};

export function Pagination({ currentPage, totalPages, onPageChange }: Props) {
  const pages = Array.from({ length: totalPages }, (_, i) => i + 1);

  return (
    <nav style={{ display: 'flex', justifyContent: 'center', marginTop: '2rem' }}>
      <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex' }}>
        <li style={{ margin: '0 0.25rem' }}>
          <button
            onClick={() => onPageChange(currentPage - 1)}
            disabled={currentPage === 1}
            style={{
              padding: '0.5rem 1rem',
              border: '1px solid #ccc',
              borderRadius: '4px',
              backgroundColor: currentPage === 1 ? '#eee' : '#fff',
              cursor: currentPage === 1 ? 'not-allowed' : 'pointer',
            }}
          >
            មុន
          </button>
        </li>
        {pages.map((page) => (
          <li key={page} style={{ margin: '0 0.25rem' }}>
            <button
              onClick={() => onPageChange(page)}
              style={{
                padding: '0.5rem 1rem',
                border: '1px solid #ccc',
                borderRadius: '4px',
                backgroundColor: page === currentPage ? '#007bff' : '#fff',
                color: page === currentPage ? '#fff' : '#000',
                cursor: 'pointer',
              }}
            >
              {page}
            </button>
          </li>
        ))}
        <li style={{ margin: '0 0.25rem' }}>
          <button
            onClick={() => onPageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            style={{
              padding: '0.5rem 1rem',
              border: '1px solid #ccc',
              borderRadius: '4px',
              backgroundColor: currentPage === totalPages ? '#eee' : '#fff',
              cursor: currentPage === totalPages ? 'not-allowed' : 'pointer',
            }}
          >
            បន្ទាប់
          </button>
        </li>
      </ul>
    </nav>
  );
}
```
អ្នកអាចប្រើវាដោយគ្រប់គ្រង `currentPage` និង `totalPages` state: `<Pagination currentPage={page} totalPages={10} onPageChange={setPage} />`។

